var PERSONALITY_SURFACE_ORDER = ['voice_live', 'text_chat', 'unified_conversation', 'operator_chat', 'dev_orb'];

function fetchPersonalityConfigs() {
    state.voiceLab.personality.loading = true;
    state.voiceLab.personality.error = null;
    renderApp();

    fetch('/api/v1/ai-personality')
        .then(function (res) {
            if (!res.ok) throw new Error('Failed to fetch personality configs: ' + res.status);
            return res.json();
        })
        .then(function (data) {
            var surfaces = {};
            (data.surfaces || []).forEach(function (s) {
                surfaces[s.surface_key] = s;
            });
            state.voiceLab.personality.surfaces = surfaces;
            state.voiceLab.personality.loaded = true;
            state.voiceLab.personality.loading = false;
            state.voiceLab.personality.error = null;
            state.voiceLab.personality.dirty = {};
            renderApp();
        })
        .catch(function (err) {
            console.error('[AI Personality] Fetch error:', err);
            state.voiceLab.personality.loading = false;
            state.voiceLab.personality.error = err.message;
            renderApp();
        });
}

function savePersonalityConfig(surfaceKey) {
    var surfaceDef = PERSONALITY_SURFACE_DEFS[surfaceKey];
    if (!surfaceDef) return;

    var config = {};
    Object.keys(surfaceDef.fields).forEach(function (fieldKey) {
        var fieldDef = surfaceDef.fields[fieldKey];
        if (fieldDef.type === 'group' && fieldDef.subfields) {
            var group = {};
            Object.keys(fieldDef.subfields).forEach(function (subKey) {
                var el = document.getElementById('personality-' + surfaceKey + '-' + fieldKey + '-' + subKey);
                if (el) group[subKey] = el.value;
            });
            config[fieldKey] = group;
        } else {
            var el = document.getElementById('personality-' + surfaceKey + '-' + fieldKey);
            if (el) config[fieldKey] = el.value;
        }
    });

    state.voiceLab.personality.saving = true;
    state.voiceLab.personality.savingSurface = surfaceKey;
    renderApp();

    fetch('/api/v1/ai-personality/' + surfaceKey, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ config: config, reason: 'Updated via Command Hub AI Personality panel' })
    })
        .then(function (res) {
            if (!res.ok) throw new Error('Failed to save: ' + res.status);
            return res.json();
        })
        .then(function (data) {
            state.voiceLab.personality.saving = false;
            state.voiceLab.personality.savingSurface = null;
            state.voiceLab.personality.surfaces[surfaceKey] = data.surface;
            delete state.voiceLab.personality.dirty[surfaceKey];
            renderApp();
            showPersonalityToast('Personality saved for ' + surfaceDef.label, 'success');
        })
        .catch(function (err) {
            console.error('[AI Personality] Save error:', err);
            state.voiceLab.personality.saving = false;
            state.voiceLab.personality.savingSurface = null;
            renderApp();
            showPersonalityToast('Failed to save: ' + err.message, 'error');
        });
}

function resetPersonalityConfig(surfaceKey) {
    var surfaceDef = PERSONALITY_SURFACE_DEFS[surfaceKey];
    if (!surfaceDef) return;
    if (!confirm('Reset "' + surfaceDef.label + '" to defaults? This will discard all customizations.')) return;

    state.voiceLab.personality.saving = true;
    state.voiceLab.personality.savingSurface = surfaceKey;
    renderApp();

    fetch('/api/v1/ai-personality/' + surfaceKey + '/reset', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' }
    })
        .then(function (res) {
            if (!res.ok) throw new Error('Failed to reset: ' + res.status);
            return res.json();
        })
        .then(function (data) {
            state.voiceLab.personality.saving = false;
            state.voiceLab.personality.savingSurface = null;
            state.voiceLab.personality.surfaces[surfaceKey] = data.surface;
            delete state.voiceLab.personality.dirty[surfaceKey];
            renderApp();
            showPersonalityToast('Reset "' + surfaceDef.label + '" to defaults', 'success');
        })
        .catch(function (err) {
            console.error('[AI Personality] Reset error:', err);
            state.voiceLab.personality.saving = false;
            state.voiceLab.personality.savingSurface = null;
            renderApp();
            showPersonalityToast('Failed to reset: ' + err.message, 'error');
        });
}

function renderVoiceLabPersonalityPanel() {
    var panel = document.createElement('div');
    panel.className = 'voice-lab-personality-panel';

    var header = document.createElement('div');
    header.className = 'personality-header';
    var title = document.createElement('h3');
    title.textContent = 'AI Personality Configuration';
    header.appendChild(title);
    var subtitle = document.createElement('p');
    subtitle.className = 'personality-subtitle';
    subtitle.textContent = 'View and modify all AI assistant personality parameters. Changes apply to new sessions.';
    header.appendChild(subtitle);
    panel.appendChild(header);

    if (!state.voiceLab.personality.loaded && !state.voiceLab.personality.loading) {
        fetchPersonalityConfigs();
    }

    if (state.voiceLab.personality.loading) {
        var loadingDiv = document.createElement('div');
        loadingDiv.className = 'personality-loading';
        loadingDiv.innerHTML = '<div class="personality-spinner"></div><span>Loading personality configs...</span>';
        panel.appendChild(loadingDiv);
        return panel;
    }

    if (state.voiceLab.personality.error) {
        var errorDiv = document.createElement('div');
        errorDiv.className = 'personality-error';
        errorDiv.innerHTML = '<strong>Error:</strong> ' + state.voiceLab.personality.error;
        var retryBtn = document.createElement('button');
        retryBtn.className = 'personality-retry-btn';
        retryBtn.textContent = 'Retry';
        retryBtn.addEventListener('click', function () {
            state.voiceLab.personality.loaded = false;
            fetchPersonalityConfigs();
        });
        errorDiv.appendChild(retryBtn);
        panel.appendChild(errorDiv);
        return panel;
    }

    PERSONALITY_SURFACE_ORDER.forEach(function (surfaceKey) {
        var surfaceDef = PERSONALITY_SURFACE_DEFS[surfaceKey];
        var surfaceData = state.voiceLab.personality.surfaces[surfaceKey] || {};
        panel.appendChild(renderPersonalitySurfaceSection(surfaceKey, surfaceDef, surfaceData));
    });

    return panel;
}

function renderPersonalitySurfaceSection(surfaceKey, surfaceDef, surfaceData) {
    var section = document.createElement('div');
    section.className = 'personality-surface-section';

    var isExpanded = state.voiceLab.personality.expandedSurface === surfaceKey;
    var isCustomized = surfaceData.is_customized || false;
    var isDirty = state.voiceLab.personality.dirty[surfaceKey] || false;
    var isSaving = state.voiceLab.personality.saving && state.voiceLab.personality.savingSurface === surfaceKey;

    var headerEl = document.createElement('div');
    headerEl.className = 'personality-surface-header' + (isExpanded ? ' expanded' : '');
    headerEl.addEventListener('click', function () {
        state.voiceLab.personality.expandedSurface = isExpanded ? null : surfaceKey;
        renderApp();
    });

    var headerLeft = document.createElement('div');
    headerLeft.className = 'personality-surface-header-left';

    var iconEl = document.createElement('span');
    iconEl.className = 'personality-surface-icon';
    iconEl.textContent = surfaceDef.icon;
    headerLeft.appendChild(iconEl);

    var labelEl = document.createElement('span');
    labelEl.className = 'personality-surface-label';
    labelEl.textContent = surfaceDef.label;
    headerLeft.appendChild(labelEl);

    if (isCustomized) {
        var badge = document.createElement('span');
        badge.className = 'personality-customized-badge';
        badge.textContent = 'Customized';
        headerLeft.appendChild(badge);
    }

    if (isDirty) {
        var dirtyDot = document.createElement('span');
        dirtyDot.className = 'personality-dirty-indicator';
        dirtyDot.title = 'Unsaved changes';
        headerLeft.appendChild(dirtyDot);
    }

    headerEl.appendChild(headerLeft);

    var chevron = document.createElement('span');
    chevron.className = 'personality-chevron';
    chevron.textContent = isExpanded ? '\u25BC' : '\u25B6';
    headerEl.appendChild(chevron);

    section.appendChild(headerEl);

    if (isExpanded) {
        var body = document.createElement('div');
        body.className = 'personality-surface-body';

        var descP = document.createElement('p');
        descP.className = 'personality-surface-desc';
        descP.textContent = surfaceDef.description + ' (source: ' + surfaceDef.sourceFile + ')';
        body.appendChild(descP);

        var currentConfig = surfaceData.config || surfaceData.defaults || {};

        Object.keys(surfaceDef.fields).forEach(function (fieldKey) {
            var fieldDef = surfaceDef.fields[fieldKey];
            body.appendChild(renderPersonalityField(surfaceKey, fieldKey, fieldDef, currentConfig));
        });

        var actions = document.createElement('div');
        actions.className = 'personality-surface-actions';

        var saveBtn = document.createElement('button');
        saveBtn.className = 'personality-save-btn';
        saveBtn.textContent = isSaving ? 'Saving...' : 'Save Changes';
        saveBtn.disabled = isSaving;
        saveBtn.addEventListener('click', function (e) {
            e.stopPropagation();
            savePersonalityConfig(surfaceKey);
        });
        actions.appendChild(saveBtn);

        var resetBtn = document.createElement('button');
        resetBtn.className = 'personality-reset-btn';
        resetBtn.textContent = 'Reset to Defaults';
        resetBtn.disabled = isSaving;
        resetBtn.addEventListener('click', function (e) {
            e.stopPropagation();
            resetPersonalityConfig(surfaceKey);
        });
        actions.appendChild(resetBtn);

        body.appendChild(actions);
        section.appendChild(body);
    }

    return section;
}

function renderPersonalityField(surfaceKey, fieldKey, fieldDef, currentConfig) {
    var wrapper = document.createElement('div');
    wrapper.className = 'personality-field';

    if (fieldDef.type === 'group' && fieldDef.subfields) {
        var groupLabel = document.createElement('div');
        groupLabel.className = 'personality-field-group-label';
        groupLabel.textContent = fieldDef.label;
        wrapper.appendChild(groupLabel);

        if (fieldDef.hint) {
            var groupHint = document.createElement('p');
            groupHint.className = 'personality-field-hint';
            groupHint.textContent = fieldDef.hint;
            wrapper.appendChild(groupHint);
        }

        var groupContainer = document.createElement('div');
        groupContainer.className = 'personality-field-group';

        var groupValue = currentConfig[fieldKey] || {};
        Object.keys(fieldDef.subfields).forEach(function (subKey) {
            var subDef = fieldDef.subfields[subKey];
            var subWrapper = document.createElement('div');
            subWrapper.className = 'personality-field personality-subfield';

            var subLabel = document.createElement('label');
            subLabel.className = 'personality-field-label';
            subLabel.setAttribute('for', 'personality-' + surfaceKey + '-' + fieldKey + '-' + subKey);
            subLabel.textContent = subDef.label;
            subWrapper.appendChild(subLabel);

            var subTextarea = document.createElement('textarea');
            subTextarea.id = 'personality-' + surfaceKey + '-' + fieldKey + '-' + subKey;
            subTextarea.className = 'personality-textarea';
            subTextarea.rows = subDef.rows || 3;
            subTextarea.value = typeof groupValue[subKey] === 'string' ? groupValue[subKey] : JSON.stringify(groupValue[subKey] || '', null, 2);
            subTextarea.addEventListener('input', function () {
                state.voiceLab.personality.dirty[surfaceKey] = true;
            });
            subWrapper.appendChild(subTextarea);
            groupContainer.appendChild(subWrapper);
        });

        wrapper.appendChild(groupContainer);
    } else {
        var label = document.createElement('label');
        label.className = 'personality-field-label';
        label.setAttribute('for', 'personality-' + surfaceKey + '-' + fieldKey);
        label.textContent = fieldDef.label;
        wrapper.appendChild(label);

        if (fieldDef.hint) {
            var hint = document.createElement('p');
            hint.className = 'personality-field-hint';
            hint.textContent = fieldDef.hint;
            wrapper.appendChild(hint);
        }

        var rawValue = currentConfig[fieldKey];
        var displayValue = typeof rawValue === 'string' ? rawValue : JSON.stringify(rawValue || '', null, 2);

        var textarea = document.createElement('textarea');
        textarea.id = 'personality-' + surfaceKey + '-' + fieldKey;
        textarea.className = 'personality-textarea';
        textarea.rows = fieldDef.rows || 3;
        textarea.value = displayValue;
        textarea.addEventListener('input', function () {
            state.voiceLab.personality.dirty[surfaceKey] = true;
        });
        wrapper.appendChild(textarea);
    }

    return wrapper;
}

function showPersonalityToast(message, type) {
    var existing = document.querySelector('.personality-toast');
    if (existing) existing.remove();

    var toast = document.createElement('div');
    toast.className = 'personality-toast personality-toast-' + (type || 'info');
    toast.textContent = message;
    document.body.appendChild(toast);
    requestAnimationFrame(function () { toast.classList.add('visible'); });
    setTimeout(function () {
        toast.classList.remove('visible');
        setTimeout(function () { toast.remove(); }, 300);
    }, 3000);
}

/**
 * VTID-01218E: Render ORB Live panel - active sessions and turn timeline
 * VTID-01218B: Enhanced with auto-refresh, visual alerts
 */
function renderVoiceLabOrbLivePanel() {
    var panel = document.createElement('div');
    panel.className = 'voice-lab-orb-live-panel';

    // VTID-01218B: Start auto-refresh when entering this panel
    startVoiceLabAutoRefresh();

    // Auto-fetch sessions (only on first render)
    if (!state.voiceLab.sessionsLoading && !state.voiceLab.sessionsFetched) {
        fetchVoiceLabSessions();
    }

    // Active Sessions Section
    var sessionsSection = document.createElement('div');
    sessionsSection.className = 'voice-lab-sessions-section';

    var sessionsHeader = document.createElement('div');
    sessionsHeader.className = 'voice-lab-section-header';

    var sessionsTitle = document.createElement('h3');
    sessionsTitle.textContent = 'Active Sessions';
    sessionsHeader.appendChild(sessionsTitle);

    // VTID-01218B: Header controls (auto-refresh toggle + refresh button)
    var headerControls = document.createElement('div');
    headerControls.className = 'voice-lab-header-controls';

    // Auto-refresh toggle
    var autoRefreshLabel = document.createElement('label');
    autoRefreshLabel.className = 'voice-lab-auto-refresh-label';
    var autoRefreshCheckbox = document.createElement('input');
    autoRefreshCheckbox.type = 'checkbox';
    autoRefreshCheckbox.checked = state.voiceLab.autoRefreshEnabled;
    autoRefreshCheckbox.addEventListener('change', function () {
        state.voiceLab.autoRefreshEnabled = autoRefreshCheckbox.checked;
        if (autoRefreshCheckbox.checked) {
            startVoiceLabAutoRefresh();
        } else {
            stopVoiceLabAutoRefresh();
        }
    });
    autoRefreshLabel.appendChild(autoRefreshCheckbox);
    autoRefreshLabel.appendChild(document.createTextNode(' Auto-refresh (2s)'));
    headerControls.appendChild(autoRefreshLabel);

    var refreshBtn = document.createElement('button');
    refreshBtn.className = 'voice-lab-refresh-btn';
    refreshBtn.textContent = 'Refresh';
    refreshBtn.addEventListener('click', function () {
        state.voiceLab.sessionsFetched = false;
        fetchVoiceLabSessions();
    });
    headerControls.appendChild(refreshBtn);

    sessionsHeader.appendChild(headerControls);
    sessionsSection.appendChild(sessionsHeader);

    // Sessions table or loading state
    if (state.voiceLab.sessionsLoading) {
        var loadingDiv = document.createElement('div');
        loadingDiv.className = 'voice-lab-loading';
        loadingDiv.textContent = 'Loading sessions...';
        sessionsSection.appendChild(loadingDiv);
    } else if (state.voiceLab.sessions.length === 0) {
        var emptyDiv = document.createElement('div');
        emptyDiv.className = 'voice-lab-empty';
        emptyDiv.textContent = 'No active voice sessions';
        sessionsSection.appendChild(emptyDiv);
    } else {
        var table = document.createElement('table');
        table.className = 'voice-lab-sessions-table';

        var thead = document.createElement('thead');
        thead.innerHTML = '<tr>' +
            '<th>Session ID</th>' +
            '<th>User</th>' +
            '<th>Platform</th>' +
            '<th>Started</th>' +
            '<th>Duration</th>' +
            '<th>Status</th>' +
            '<th>Turns</th>' +
            '<th>Alerts</th>' +
            '<th>Actions</th>' +
            '</tr>';
        table.appendChild(thead);

        var tbody = document.createElement('tbody');
        state.voiceLab.sessions.forEach(function (session) {
            var row = document.createElement('tr');
            row.className = session.connected ? 'session-active' : 'session-ended';

            var startedAt = session.startedAt ? new Date(session.startedAt).toLocaleTimeString() : '-';

            // User display
            var userDisplay = session.userDisplayName || session.userEmail || (session.userId ? session.userId.substring(0, 8) : 'Anonymous');
            var userTitle = session.userEmail || session.userId || 'Anonymous';

            // Platform badge
            var platformDisplay = session.platform || 'unknown';
            var platformClass = 'platform-badge platform-' + platformDisplay.toLowerCase();

            // VTID-01218B: Visual alerts
            var alerts = [];
            var alertClass = '';
            if (session.turnCount === 0 && !session.connected) {
                alerts.push('No turns');
                alertClass = 'alert-red';
            }
            if (session.interruptedCount > 0) {
                alerts.push(session.interruptedCount + ' interrupts');
                if (!alertClass) alertClass = 'alert-orange';
            }
            if (session.errorCount > 0) {
                alerts.push(session.errorCount + ' errors');
                if (!alertClass) alertClass = 'alert-red';
            }

            var alertsHtml = alerts.length > 0
                ? '<span class="voice-lab-alert ' + alertClass + '">' + alerts.join(', ') + '</span>'
                : '<span class="voice-lab-ok">OK</span>';

            // VTID-01218B: Turns with color coding
            var turnsClass = '';
            if (session.turnCount === 0 && !session.connected) {
                turnsClass = 'turns-zero';
            }

            // Duration
            var durationMs = session.durationMs;
            if (!durationMs && session.startedAt && session.endedAt) {
                durationMs = new Date(session.endedAt).getTime() - new Date(session.startedAt).getTime();
            }
            var durationStr = durationMs ? formatDuration(durationMs) : (session.connected ? 'Live' : '-');

            row.innerHTML = '<td class="session-id">' + (session.sessionId || '-').substring(0, 8) + '...</td>' +
                '<td class="session-user" title="' + userTitle + '">' + userDisplay + '</td>' +
                '<td><span class="' + platformClass + '">' + platformDisplay + '</span></td>' +
                '<td>' + startedAt + '</td>' +
                '<td>' + durationStr + '</td>' +
                '<td class="session-status">' + (session.connected ? '<span class="status-active">Active</span>' : '<span class="status-ended">Ended</span>') + '</td>' +
                '<td class="' + turnsClass + '">' + (session.turnCount || 0) + '</td>' +
                '<td>' + alertsHtml + '</td>' +
                '<td></td>';

            // Add view details button in the Actions cell
            var actionsCell = row.querySelector('td:last-child');
            var viewBtn = document.createElement('button');
            viewBtn.className = 'voice-lab-view-btn';
            viewBtn.textContent = 'Details';
            viewBtn.setAttribute('data-session-id', session.sessionId);
            viewBtn.addEventListener('click', function () {
                state.voiceLab.selectedSession = session.sessionId;
                fetchVoiceLabSessionDetails(session.sessionId);
            });
            actionsCell.appendChild(viewBtn);

            tbody.appendChild(row);
        });
        table.appendChild(tbody);
        sessionsSection.appendChild(table);

        // Load More button
        if (state.voiceLab.sessionsHasMore) {
            var loadMoreDiv = document.createElement('div');
            loadMoreDiv.className = 'voice-lab-load-more';
            var loadMoreBtn = document.createElement('button');
            loadMoreBtn.className = 'voice-lab-load-more-btn';
            loadMoreBtn.textContent = state.voiceLab.sessionsLoadingMore ? 'Loading...' : 'Load More Sessions';
            loadMoreBtn.disabled = state.voiceLab.sessionsLoadingMore;
            loadMoreBtn.addEventListener('click', function () {
                fetchVoiceLabSessions(true);
            });
            loadMoreDiv.appendChild(loadMoreBtn);
            sessionsSection.appendChild(loadMoreDiv);
        }
    }

    panel.appendChild(sessionsSection);

    // Session Details Side Drawer (fixed overlay, appended to body)
    if (state.voiceLab.selectedSession) {
        // Remove any existing drawer first
        var existingOverlay = document.querySelector('.voice-lab-drawer-overlay');
        if (existingOverlay) existingOverlay.remove();
        document.body.appendChild(renderVoiceLabSessionDrawer());
    } else {
        // Clean up overlay if session deselected
        var staleOverlay = document.querySelector('.voice-lab-drawer-overlay');
        if (staleOverlay) staleOverlay.remove();
    }

    return panel;
}

/**
 * VTID-01218E: Render session details drawer
 * VTID-01218B: Enhanced with actual session details and turn timeline
 */
function renderVoiceLabSessionDrawer() {
    function closeDrawer() {
        state.voiceLab.selectedSession = null;
        state.voiceLab.selectedSessionDetails = null;
        state.voiceLab.selectedSessionTurns = [];
        state.voiceLab.selectedSessionDiagnostics = null;
        var overlay = document.querySelector('.voice-lab-drawer-overlay');
        if (overlay) overlay.remove();
        renderApp();
    }

    // Fixed overlay (click backdrop to close)
    var overlay = document.createElement('div');
    overlay.className = 'voice-lab-drawer-overlay';
    overlay.addEventListener('click', function (e) {
        if (e.target === overlay) closeDrawer();
    });

    // Side panel
    var drawer = document.createElement('div');
    drawer.className = 'voice-lab-side-drawer';

    var drawerHeader = document.createElement('div');
    drawerHeader.className = 'voice-lab-drawer-header';

    var drawerTitle = document.createElement('h3');
    drawerTitle.textContent = 'Session Details';
    drawerHeader.appendChild(drawerTitle);

    var closeBtn = document.createElement('button');
    closeBtn.className = 'drawer-close-btn';
    closeBtn.innerHTML = '&#x2715;';
    closeBtn.addEventListener('click', closeDrawer);
    drawerHeader.appendChild(closeBtn);

    drawer.appendChild(drawerHeader);

    var drawerContent = document.createElement('div');
    drawerContent.className = 'voice-lab-drawer-content';

    // Loading state
    if (state.voiceLab.sessionDetailsLoading) {
        var loadingDiv = document.createElement('div');
        loadingDiv.className = 'voice-lab-loading';
        loadingDiv.textContent = 'Loading session details...';
        drawerContent.appendChild(loadingDiv);
        drawer.appendChild(drawerContent);
        overlay.appendChild(drawer);
        return overlay;
    }

    var details = state.voiceLab.selectedSessionDetails;

    // Helper: create a grouped section with key-value pairs
    function createDetailSection(title, pairs) {
        var section = document.createElement('div');
        section.className = 'session-detail-section';
        var heading = document.createElement('div');
        heading.className = 'session-detail-section-title';
        heading.textContent = title;
        section.appendChild(heading);
        pairs.forEach(function (pair) {
            if (pair.value === undefined || pair.value === null || pair.value === '') return;
            var row = document.createElement('div');
            row.className = 'session-detail-row' + (pair.className ? ' ' + pair.className : '');
            row.innerHTML = '<span class="detail-label">' + pair.label + '</span><span class="detail-value">' + pair.value + '</span>';
            section.appendChild(row);
        });
        return section;
    }

    if (details) {
        // === Diagnostic Analysis (shown at top when issues detected) ===
        var diagnostics = [];
        var sessionDurationSec = 0;
        if (details.started_at && details.ended_at) {
            sessionDurationSec = (new Date(details.ended_at).getTime() - new Date(details.started_at).getTime()) / 1000;
        }

        // No audio input received
        if (details.status === 'ended' && (details.audio_in_chunks || 0) === 0 && sessionDurationSec > 10) {
            diagnostics.push({
                severity: 'critical',
                title: 'No microphone audio received',
                detail: 'The server received 0 audio chunks from the client during a ' + Math.round(sessionDurationSec) + 's session. ' +
                    'Possible causes: microphone permission denied, browser blocked mic access, audio stream failed to initialize, or client-side WebSocket audio pipe broken.'
            });
        }

        // Audio out but no audio in (one-way audio)
        if (details.status === 'ended' && (details.audio_out_chunks || 0) > 0 && (details.audio_in_chunks || 0) === 0 && sessionDurationSec > 10) {
            diagnostics.push({
                severity: 'critical',
                title: 'One-way audio detected',
                detail: 'Server sent ' + details.audio_out_chunks + ' audio chunks (likely greeting) but never received audio back. ' +
                    'The user heard the ORB speak but could not be heard. This typically indicates a client-side mic/audio capture failure.'
            });
        }

        // Session lasted but no user turns
        if (details.status === 'ended' && (details.user_turns || 0) === 0 && sessionDurationSec > 30) {
            diagnostics.push({
                severity: 'warning',
                title: 'No user speech detected in ' + Math.round(sessionDurationSec) + 's session',
                detail: 'The user was connected for over 30 seconds but no speech was transcribed. ' +
                    'If the user was speaking, their audio may not have reached the server or VAD (voice activity detection) never triggered.'
            });
        }

        // Zero turns but session ended normally
        if (details.status === 'ended' && (details.turn_count || 0) === 0 && sessionDurationSec > 15) {
            diagnostics.push({
                severity: 'warning',
                title: 'Session ended with zero conversation turns',
                detail: 'No back-and-forth conversation occurred. The user may have been stuck without knowing what went wrong. ' +
                    'Consider adding client-side timeout feedback when no response is received.'
            });
        }

        // High interruption rate
        var totalTurns = details.turn_count || 0;
        if (totalTurns > 2 && (details.interrupted_count || 0) > totalTurns * 0.5) {
            diagnostics.push({
                severity: 'warning',
                title: 'High interruption rate (' + details.interrupted_count + '/' + totalTurns + ' turns)',
                detail: 'More than half of conversation turns were interrupted. This may indicate VAD sensitivity issues, ' +
                    'background noise triggering false speech detection, or the model response latency causing user to repeat.'
            });
        }

        // Errors present
        if ((details.error_count || 0) > 0) {
            diagnostics.push({
                severity: 'critical',
                title: details.error_count + ' error(s) during session',
                detail: 'Errors occurred during this session. Check the Errors section below for details.'
            });
        }

        // Very short session (< 5s) that ended
        if (details.status === 'ended' && sessionDurationSec > 0 && sessionDurationSec < 5) {
            diagnostics.push({
                severity: 'warning',
                title: 'Session lasted only ' + sessionDurationSec.toFixed(1) + 's',
                detail: 'This session was extremely short. Possible connection failure, auth issue, or user immediately disconnected.'
            });
        }

        // Low audio out relative to turns (model may have been silent)
        if (totalTurns > 2 && (details.audio_out_chunks || 0) < totalTurns * 5) {
            diagnostics.push({
                severity: 'warning',
                title: 'Low audio output for ' + totalTurns + ' turns',
                detail: 'Very few audio chunks were sent to the client relative to the number of turns. ' +
                    'The model may have responded with very short or empty audio, or TTS may have failed silently.'
            });
        }

        // Render diagnostics section
        if (diagnostics.length > 0) {
            var diagSection = document.createElement('div');
            diagSection.className = 'session-diagnostics';

            var diagHeader = document.createElement('div');
            diagHeader.className = 'session-diagnostics-header';
            var hasCritical = diagnostics.some(function (d) { return d.severity === 'critical'; });
            diagHeader.innerHTML = (hasCritical ? '\u26A0 ' : '\u2139 ') + 'Diagnostic Analysis (' + diagnostics.length + ' issue' + (diagnostics.length > 1 ? 's' : '') + ')';
            diagSection.appendChild(diagHeader);

            diagnostics.forEach(function (diag) {
                var item = document.createElement('div');
                item.className = 'session-diagnostic-item diagnostic-' + diag.severity;

                var titleEl = document.createElement('div');
                titleEl.className = 'diagnostic-title';
                titleEl.textContent = (diag.severity === 'critical' ? '\u2716 ' : '\u25B3 ') + diag.title;
                item.appendChild(titleEl);

                var detailEl = document.createElement('div');
                detailEl.className = 'diagnostic-detail';
                detailEl.textContent = diag.detail;
                item.appendChild(detailEl);

                diagSection.appendChild(item);
            });

            drawerContent.appendChild(diagSection);

            // "Investigate with Claude" button — triggers Managed Agents triage
            var investigateBtn = document.createElement('button');
            investigateBtn.className = 'btn btn-primary triage-investigate-btn';
            investigateBtn.textContent = 'Investigate with Claude';
            investigateBtn.onclick = function () {
                investigateBtn.disabled = true;
                investigateBtn.textContent = 'Starting investigation...';

                // Collect diagnostic flags
                var flagTexts = diagnostics.map(function (d) { return d.title; });

                fetch('/api/v1/agents/triage/investigate', {
                    method: 'POST',
                    headers: Object.assign({ 'Content-Type': 'application/json' }, buildContextHeaders({})),
                    body: JSON.stringify({
                        session_id: state.voiceLab.selectedSession,
                        diagnostic_summary: diagnostics.map(function (d) {
                            return d.severity + ': ' + d.title + ' — ' + d.detail;
                        }).join('\n'),
                        flags: flagTexts,
                        metrics: {
                            duration_ms: details.duration_ms,
                            audio_in_chunks: details.audio_in_chunks,
                            audio_out_chunks: details.audio_out_chunks,
                            turn_count: details.turn_count,
                            error_count: details.error_count,
                            interrupted_count: details.interrupted_count
                        }
                    })
                }).then(function (r) { return r.json(); }).then(function (result) {
                    if (!result.ok) {
                        investigateBtn.textContent = 'Investigation failed';
                        investigateBtn.disabled = false;
                        showToast(result.error || 'Failed to start investigation', 'error');
                        return;
                    }
                    investigateBtn.textContent = 'Investigation running...';

                    // Create the streaming panel
                    var panel = document.createElement('div');
                    panel.className = 'triage-panel';
                    panel.innerHTML = '<div class="triage-panel-header">Claude Investigation — ' +
                        escapeHtml(state.voiceLab.selectedSession) + '</div>' +
                        '<div class="triage-panel-body" id="triage-output"></div>';
                    investigateBtn.parentNode.insertBefore(panel, investigateBtn.nextSibling);

                    var outputEl = document.getElementById('triage-output');

                    // Connect to the SSE stream
                    var eventSource = new EventSource(result.stream_url);

                    eventSource.addEventListener('agent.message', function (e) {
                        var data = JSON.parse(e.data);
                        if (data.content) {
                            data.content.forEach(function (block) {
                                if (block.type === 'text') {
                                    var p = document.createElement('div');
                                    p.className = 'triage-message';
                                    p.textContent = block.text;
                                    outputEl.appendChild(p);
                                    outputEl.scrollTop = outputEl.scrollHeight;
                                }
                            });
                        }
                    });

                    eventSource.addEventListener('agent.thinking', function (e) {
                        var data = JSON.parse(e.data);
                        var div = document.createElement('div');
                        div.className = 'triage-thinking';
                        div.textContent = '[thinking] ' + (data.thinking || '').substring(0, 200) + '...';
                        outputEl.appendChild(div);
                    });

                    eventSource.addEventListener('agent.custom_tool_use', function (e) {
                        var data = JSON.parse(e.data);
                        var div = document.createElement('div');
                        div.className = 'triage-tool-call';
                        div.textContent = 'Calling: ' + data.tool_name + '(' + JSON.stringify(data.input || {}) + ')';
                        outputEl.appendChild(div);
                    });

                    eventSource.addEventListener('agent.tool_use', function (e) {
                        var data = JSON.parse(e.data);
                        var div = document.createElement('div');
                        div.className = 'triage-tool-call';
                        div.textContent = 'Using: ' + (data.name || 'tool');
                        outputEl.appendChild(div);
                    });

                    eventSource.addEventListener('session.idle', function () {
                        investigateBtn.textContent = 'Investigation complete';
                        eventSource.close();
                    });

                    eventSource.addEventListener('session.terminated', function () {
                        investigateBtn.textContent = 'Investigation ended';
                        eventSource.close();
                    });

                    eventSource.addEventListener('session.error', function (e) {
                        var data = JSON.parse(e.data);
                        var div = document.createElement('div');
                        div.className = 'triage-error';
                        div.textContent = 'Error: ' + (data.error || 'unknown');
                        outputEl.appendChild(div);
                    });

                    eventSource.addEventListener('done', function () {
                        investigateBtn.textContent = 'Investigation complete';
                        investigateBtn.disabled = false;
                        eventSource.close();
                    });

                    eventSource.onerror = function () {
                        investigateBtn.textContent = 'Investigate with Claude';
                        investigateBtn.disabled = false;
                        eventSource.close();
                    };
                }).catch(function (err) {
                    investigateBtn.textContent = 'Investigate with Claude';
                    investigateBtn.disabled = false;
                    showToast('Failed: ' + err.message, 'error');
                });
            };
            diagSection.appendChild(investigateBtn);

        } else if (details.status === 'ended') {
            var healthySection = document.createElement('div');
            healthySection.className = 'session-diagnostics session-diagnostics-healthy';
            healthySection.innerHTML = '<div class="session-diagnostics-header">\u2714 Session Healthy</div>' +
                '<div class="diagnostic-detail">No anomalies detected. Audio flow, turn counts, and session timing all look normal.</div>';
            drawerContent.appendChild(healthySection);
        }

        // Section 1: Session Overview
        var durationMs = details.duration_ms;
        if (!durationMs && details.started_at && details.ended_at) {
            durationMs = new Date(details.ended_at).getTime() - new Date(details.started_at).getTime();
        }
        var durationDisplay = durationMs ? formatDuration(durationMs) : '-';
        var startedDisplay = details.started_at ? new Date(details.started_at).toLocaleString() : '-';
        var endedDisplay = details.ended_at ? new Date(details.ended_at).toLocaleString() : '-';
        var statusHtml = details.status === 'active'
            ? '<span class="status-active">Active</span>'
            : '<span class="status-ended">Ended</span>';

        drawerContent.appendChild(createDetailSection('Session Overview', [
            { label: 'Session ID', value: state.voiceLab.selectedSession },
            { label: 'Status', value: statusHtml },
            { label: 'Started', value: startedDisplay },
            { label: 'Ended', value: endedDisplay },
            { label: 'Duration', value: durationDisplay }
        ]));

        // Section 2: User & Context
        drawerContent.appendChild(createDetailSection('User & Context', [
            { label: 'User', value: details.user_display_name || details.user_email || details.user_id || 'Anonymous' },
            { label: 'Email', value: details.user_email || '-' },
            { label: 'Role', value: details.user_role || '-' },
            { label: 'Language', value: details.lang || '-' },
            { label: 'Voice', value: details.voice_style || details.voice || '-' }
        ]));

        // Section 3: Platform
        var modalitiesDisplay = details.modalities ? details.modalities.join(', ') : '-';
        drawerContent.appendChild(createDetailSection('Platform', [
            { label: 'Platform', value: details.platform || 'unknown' },
            { label: 'Origin', value: details.origin || '-' },
            { label: 'Transport', value: details.transport || '-' },
            { label: 'Modalities', value: modalitiesDisplay },
            { label: 'Input Rate', value: details.input_rate ? details.input_rate + ' Hz' : '-' },
            { label: 'Output Rate', value: details.output_rate ? details.output_rate + ' Hz' : '-' }
        ]));

        // Section 4: Conversation
        drawerContent.appendChild(createDetailSection('Conversation', [
            { label: 'Total Turns', value: details.turn_count || 0 },
            { label: 'User Turns (Questions)', value: details.user_turns || 0 },
            { label: 'Model Turns (Answers)', value: details.model_turns || 0 },
            { label: 'Audio In', value: (details.audio_in_chunks || 0) + ' chunks' },
            { label: 'Audio Out', value: (details.audio_out_chunks || 0) + ' chunks' },
            { label: 'Interruptions', value: details.interrupted_count || 0, className: details.interrupted_count > 0 ? 'alert-orange' : '' },
            { label: 'Video Frames', value: details.video_frames || '-' }
        ]));

        // Section 5: Errors
        if (details.error_count > 0 || (details.errors && details.errors.length > 0)) {
            var errorsSection = document.createElement('div');
            errorsSection.className = 'session-detail-section session-errors-section';
            var errorsHeading = document.createElement('div');
            errorsHeading.className = 'session-detail-section-title alert-red';
            errorsHeading.textContent = 'Errors (' + (details.errors ? details.errors.length : details.error_count) + ')';
            errorsSection.appendChild(errorsHeading);

            (details.errors || []).forEach(function (err) {
                var errRow = document.createElement('div');
                errRow.className = 'session-error-item';
                var errTime = err.timestamp ? new Date(err.timestamp).toLocaleTimeString() : '-';
                errRow.innerHTML = '<span class="error-time">' + errTime + '</span>' +
                    '<span class="error-code">' + (err.error_code || 'unknown') + '</span>' +
                    '<span class="error-msg">' + (err.error_message || 'Unknown error') + '</span>';
                errorsSection.appendChild(errRow);
            });
            drawerContent.appendChild(errorsSection);
        } else {
            drawerContent.appendChild(createDetailSection('Errors', [
                { label: 'Status', value: '<span class="voice-lab-ok">No errors</span>' }
            ]));
        }

        // Section 6: Tool Executions
        if (details.tool_executions && details.tool_executions.length > 0) {
            var toolsSection = document.createElement('div');
            toolsSection.className = 'session-detail-section';
            var toolsHeading = document.createElement('div');
            toolsHeading.className = 'session-detail-section-title';
            toolsHeading.textContent = 'Tool Executions (' + details.tool_executions.length + ')';
            toolsSection.appendChild(toolsHeading);

            details.tool_executions.forEach(function (tool) {
                var toolRow = document.createElement('div');
                toolRow.className = 'session-tool-item ' + (tool.success ? 'tool-success' : 'tool-failed');
                var toolTime = tool.timestamp ? new Date(tool.timestamp).toLocaleTimeString() : '-';
                toolRow.innerHTML = '<span class="tool-time">' + toolTime + '</span>' +
                    '<span class="tool-name">' + tool.tool_name + '</span>' +
                    '<span class="tool-status">' + (tool.success ? 'OK' : 'FAILED') + '</span>';
                toolsSection.appendChild(toolRow);
            });
            drawerContent.appendChild(toolsSection);
        }
    } else {
        var noDetails = document.createElement('p');
        noDetails.className = 'voice-lab-no-turns';
        noDetails.textContent = 'No session details available.';
        drawerContent.appendChild(noDetails);
    }

    // Turn Timeline
    var turns = state.voiceLab.selectedSessionTurns;
    if (turns && turns.length > 0) {
        var turnsSection = document.createElement('div');
        turnsSection.className = 'voice-lab-turns-section';

        var turnsTitle = document.createElement('h4');
        turnsTitle.textContent = 'Turn Timeline (' + turns.length + ' turns)';
        turnsSection.appendChild(turnsTitle);

        var turnsTable = document.createElement('table');
        turnsTable.className = 'voice-lab-turns-table';

        var turnsHead = document.createElement('thead');
        turnsHead.innerHTML = '<tr>' +
            '<th>#</th>' +
            '<th>Started</th>' +
            '<th>Duration</th>' +
            '<th>First Audio</th>' +
            '<th>End Source</th>' +
            '<th>Status</th>' +
            '</tr>';
        turnsTable.appendChild(turnsHead);

        var turnsBody = document.createElement('tbody');
        turns.forEach(function (turn) {
            var row = document.createElement('tr');

            var startTime = turn.started_at ? new Date(turn.started_at).toLocaleTimeString() : '-';
            var durationMs = turn.turn_ms ? turn.turn_ms + 'ms' : '-';
            var firstAudioMs = turn.first_audio_ms ? turn.first_audio_ms + 'ms' : '-';
            var endSource = turn.end_turn_source || '-';

            // VTID-01218B: Visual alerts for latency
            var firstAudioClass = '';
            if (turn.first_audio_ms && turn.first_audio_ms > 1200) {
                firstAudioClass = 'alert-red';
            } else if (turn.first_audio_ms && turn.first_audio_ms > 800) {
                firstAudioClass = 'alert-orange';
            }

            // Status indicators
            var statusHtml = '';
            if (turn.was_interrupted) {
                statusHtml = '<span class="turn-status alert-orange">Interrupted</span>';
            } else if (turn.playback_clear_triggered) {
                statusHtml = '<span class="turn-status alert-orange">Cleared</span>';
            } else if (turn.ended_at) {
                statusHtml = '<span class="turn-status status-ok">Complete</span>';
            } else {
                statusHtml = '<span class="turn-status status-active">In Progress</span>';
            }

            row.innerHTML = '<td>' + turn.turn_number + '</td>' +
                '<td>' + startTime + '</td>' +
                '<td>' + durationMs + '</td>' +
                '<td class="' + firstAudioClass + '">' + firstAudioMs + '</td>' +
                '<td>' + endSource + '</td>' +
                '<td>' + statusHtml + '</td>';

            turnsBody.appendChild(row);
        });
        turnsTable.appendChild(turnsBody);
        turnsSection.appendChild(turnsTable);
        drawerContent.appendChild(turnsSection);
    } else if (!state.voiceLab.sessionDetailsLoading) {
        var noTurns = document.createElement('p');
        noTurns.className = 'voice-lab-no-turns';
        noTurns.textContent = 'No turns recorded for this session.';
        drawerContent.appendChild(noTurns);
    }

    // Pipeline Diagnostics Section
    drawerContent.appendChild(renderVoiceLabPipelineDiagnostics());

    drawer.appendChild(drawerContent);
    overlay.appendChild(drawer);
    return overlay;
}

/**
 * Render pipeline diagnostics section for the session detail drawer.
 * Shows orb.live.diag events: stall analysis, flow checkmarks, timeline.
 */
function renderVoiceLabPipelineDiagnostics() {
    var section = document.createElement('div');
    section.className = 'session-detail-section';

    var heading = document.createElement('div');
    heading.className = 'session-detail-section-title';
    heading.textContent = 'Pipeline Diagnostics';
    section.appendChild(heading);

    var diagData = state.voiceLab.selectedSessionDiagnostics;
    if (!diagData || !diagData.diagnostics || diagData.diagnostics.length === 0) {
        var empty = document.createElement('p');
        empty.className = 'voice-lab-no-turns';
        empty.textContent = 'No pipeline diagnostic events recorded for this session.';
        section.appendChild(empty);
        return section;
    }

    var diags = diagData.diagnostics;
    var analysis = diagData.analysis;

    // Stall detection banner
    if (analysis && analysis.stall_detected) {
        var alertDiv = document.createElement('div');
        alertDiv.className = 'session-diagnostic-item diagnostic-critical';
        alertDiv.innerHTML = '<div class="diagnostic-title">\u2716 STALL: ' + escapeHtml(analysis.stall_type || '') + '</div>' +
            '<div class="diagnostic-detail">' + escapeHtml(analysis.stall_description || '') + '</div>';
        section.appendChild(alertDiv);
    } else if (analysis && analysis.total_events > 0) {
        var okDiv = document.createElement('div');
        okDiv.className = 'session-diagnostics session-diagnostics-healthy';
        okDiv.style.marginBottom = '0.75rem';
        okDiv.innerHTML = '<div class="session-diagnostics-header">\u2714 Pipeline OK (' + analysis.total_events + ' events)</div>';
        section.appendChild(okDiv);
    }

    // Pipeline flow checkmarks
    if (analysis && analysis.flow) {
        var flowDiv = document.createElement('div');
        flowDiv.className = 'pipeline-flow-badges';
        flowDiv.style.cssText = 'display:flex;flex-wrap:wrap;gap:0.4rem;margin-bottom:0.75rem;';

        var stages = [
            { key: 'greeting_sent', label: 'Greeting' },
            { key: 'model_start_speaking', label: 'Model Speaking' },
            { key: 'turn_complete', label: 'Turn Complete' },
            { key: 'input_transcription', label: 'User Input' },
            { key: 'watchdog_fired', label: 'Watchdog Fired', isError: true },
            { key: 'upstream_ws_error', label: 'WS Error', isError: true },
            { key: 'upstream_ws_close', label: 'WS Close', isError: true }
        ];

        for (var i = 0; i < stages.length; i++) {
            var st = stages[i];
            var reached = analysis.flow[st.key];
            var badge = document.createElement('span');
            if (reached && st.isError) {
                badge.style.cssText = 'display:inline-flex;align-items:center;gap:0.25rem;padding:0.25rem 0.5rem;border-radius:0.25rem;font-size:0.7rem;font-weight:600;background:rgba(127,29,29,0.4);color:#fca5a5;border:1px solid rgba(220,38,38,0.4);';
                badge.textContent = '! ' + st.label;
            } else if (reached) {
                badge.style.cssText = 'display:inline-flex;align-items:center;gap:0.25rem;padding:0.25rem 0.5rem;border-radius:0.25rem;font-size:0.7rem;font-weight:600;background:rgba(22,101,52,0.3);color:#86efac;border:1px solid rgba(34,197,94,0.3);';
                badge.textContent = '\u2713 ' + st.label;
            } else {
                badge.style.cssText = 'display:inline-flex;align-items:center;gap:0.25rem;padding:0.25rem 0.5rem;border-radius:0.25rem;font-size:0.7rem;font-weight:600;background:rgba(51,65,85,0.3);color:#64748b;border:1px solid #334155;';
                badge.textContent = '\u2717 ' + st.label;
            }
            flowDiv.appendChild(badge);
        }
        section.appendChild(flowDiv);
    }

    // Suspicious gaps
    if (analysis && analysis.suspicious_gaps && analysis.suspicious_gaps.length > 0) {
        var gapsDiv = document.createElement('div');
        gapsDiv.style.cssText = 'margin-bottom:0.75rem;padding:0.5rem 0.6rem;background:rgba(245,158,11,0.1);border:1px solid rgba(245,158,11,0.3);border-radius:0.375rem;';
        var gapsTitle = document.createElement('div');
        gapsTitle.style.cssText = 'font-size:0.7rem;font-weight:600;color:#fbbf24;margin-bottom:0.3rem;';
        gapsTitle.textContent = 'Suspicious Gaps (>5s)';
        gapsDiv.appendChild(gapsTitle);
        for (var g = 0; g < analysis.suspicious_gaps.length; g++) {
            var gap = analysis.suspicious_gaps[g];
            var gapItem = document.createElement('div');
            gapItem.style.cssText = 'font-size:0.7rem;color:#d4d4d8;margin-top:0.15rem;';
            gapItem.innerHTML = escapeHtml(gap.from || '?') + ' \u2192 ' + escapeHtml(gap.to || '?') +
                ': <strong>' + (gap.gap_ms / 1000).toFixed(1) + 's</strong>';
            gapsDiv.appendChild(gapItem);
        }
        section.appendChild(gapsDiv);
    }

    // Event timeline
    var timelineTitle = document.createElement('div');
    timelineTitle.style.cssText = 'font-size:0.7rem;font-weight:600;color:#94a3b8;margin-bottom:0.4rem;';
    timelineTitle.textContent = 'Event Timeline (' + diags.length + ' events)';
    section.appendChild(timelineTitle);

    var timeline = document.createElement('div');
    timeline.style.cssText = 'position:relative;';

    var firstTs = diags[0].ts;
    for (var j = 0; j < diags.length; j++) {
        var d = diags[j];
        var relMs = d.ts ? (d.ts - firstTs) : 0;
        var relLabel = '+' + (relMs / 1000).toFixed(2) + 's';
        var stageLabel = d.stage || 'unknown';

        var eventDiv = document.createElement('div');
        eventDiv.style.cssText = 'display:flex;align-items:flex-start;gap:0.5rem;padding:0.3rem 0;border-left:2px solid #334155;margin-left:0.3rem;padding-left:0.8rem;position:relative;';
        if (j === diags.length - 1) eventDiv.style.borderLeftColor = 'transparent';

        // Dot
        var dot = document.createElement('div');
        var dotColor = '#3b82f6';
        if (stageLabel === 'watchdog_fired' || stageLabel === 'upstream_ws_error' || stageLabel === 'audio_forward_failed' || stageLabel === 'audio_no_ws') {
            dotColor = '#ef4444';
        } else if (stageLabel === 'upstream_ws_close') {
            dotColor = '#f59e0b';
        } else if (stageLabel === 'turn_complete') {
            dotColor = '#22c55e';
        }
        dot.style.cssText = 'position:absolute;left:-0.25rem;top:0.45rem;width:0.5rem;height:0.5rem;border-radius:50%;background:' + dotColor + ';flex-shrink:0;';
        eventDiv.appendChild(dot);

        // Content
        var content = document.createElement('div');
        content.style.cssText = 'min-width:0;flex:1;';

        var header = document.createElement('div');
        header.style.cssText = 'display:flex;justify-content:space-between;align-items:baseline;';
        var stageSpan = document.createElement('span');
        stageSpan.style.cssText = 'font-family:monospace;font-size:0.7rem;font-weight:600;color:#e2e8f0;';
        stageSpan.textContent = stageLabel;
        var timeSpan = document.createElement('span');
        timeSpan.style.cssText = 'font-family:monospace;font-size:0.6rem;color:#64748b;';
        timeSpan.textContent = relLabel;
        header.appendChild(stageSpan);
        header.appendChild(timeSpan);
        content.appendChild(header);

        // Meta info
        var meta = [];
        if (d.turn_count !== undefined) meta.push('turns:' + d.turn_count);
        if (d.audio_in !== undefined) meta.push('in:' + d.audio_in);
        if (d.audio_out !== undefined) meta.push('out:' + d.audio_out);
        if (d.is_model_speaking) meta.push('speaking');
        if (d.has_watchdog) meta.push('watchdog-active');
        if (!d.has_upstream_ws) meta.push('NO-WS');
        if (!d.has_sse) meta.push('NO-SSE');
        if (d.reason) meta.push(d.reason);
        if (d.error) meta.push(d.error);
        if (d.tool_name) meta.push('tool:' + d.tool_name);

        if (meta.length > 0) {
            var metaDiv = document.createElement('div');
            metaDiv.style.cssText = 'font-size:0.6rem;color:#94a3b8;margin-top:0.1rem;word-break:break-all;';
            metaDiv.textContent = meta.join(' | ');
            content.appendChild(metaDiv);
        }

        eventDiv.appendChild(content);
        timeline.appendChild(eventDiv);
    }

    section.appendChild(timeline);
    return section;
}

/**
 * VTID-01218E: Fetch Voice LAB sessions from API
 */
function fetchVoiceLabSessions(append) {
    if (!append) {
        state.voiceLab.sessionsLoading = true;
        renderApp();
    } else {
        state.voiceLab.sessionsLoadingMore = true;
        renderApp();
    }

    var offset = append ? state.voiceLab.sessions.length : 0;
    fetch('/api/v1/voice-lab/live/sessions?offset=' + offset)
        .then(function (resp) {
            if (!resp.ok) throw new Error('Failed to fetch sessions');
            return resp.json();
        })
        .then(function (data) {
            // VTID-01218E: Map API response (snake_case) to frontend format (camelCase)
            var sessions = (data.sessions || []).map(function (s) {
                return {
                    sessionId: s.session_id,
                    connected: s.status === 'active',
                    startedAt: s.started_at,
                    endedAt: s.ended_at,
                    lastActivity: s.ended_at || s.started_at,
                    turnCount: s.turn_count,
                    durationMs: s.duration_ms,
                    lang: s.lang,
                    errorCount: s.error_count,
                    interruptedCount: s.interrupted_count,
                    userId: s.user_id,
                    userEmail: s.user_email,
                    userDisplayName: s.user_display_name,
                    userRole: s.user_role,
                    platform: s.platform
                };
            });
            if (append) {
                state.voiceLab.sessions = state.voiceLab.sessions.concat(sessions);
            } else {
                state.voiceLab.sessions = sessions;
            }
            state.voiceLab.sessionsHasMore = data.has_more || false;
            state.voiceLab.sessionsLoading = false;
            state.voiceLab.sessionsLoadingMore = false;
            state.voiceLab.sessionsFetched = true;
            renderApp();
        })
        .catch(function (err) {
            console.error('[VTID-01218E] Error fetching sessions:', err);
            if (!append) state.voiceLab.sessions = [];
            state.voiceLab.sessionsLoading = false;
            state.voiceLab.sessionsLoadingMore = false;
            state.voiceLab.sessionsFetched = true;
            renderApp();
        });
}

/**
 * VTID-01218B: Fetch session details and turns from API
 */
function fetchVoiceLabSessionDetails(sessionId) {
    console.log('[VTID-01218B] Fetching details for session:', sessionId);
    state.voiceLab.sessionDetailsLoading = true;
    state.voiceLab.selectedSessionDetails = null;
    state.voiceLab.selectedSessionTurns = [];
    state.voiceLab.selectedSessionDiagnostics = null;
    renderApp();

    // Fetch session details, turns, and pipeline diagnostics in parallel
    Promise.all([
        fetch('/api/v1/voice-lab/live/sessions/' + sessionId).then(function (r) { return r.json(); }),
        fetch('/api/v1/voice-lab/live/sessions/' + sessionId + '/turns').then(function (r) { return r.json(); }),
        fetch('/api/v1/voice-lab/live/sessions/' + sessionId + '/diagnostics').then(function (r) { return r.json(); }).catch(function () { return null; })
    ])
        .then(function (results) {
            var detailsResp = results[0];
            var turnsResp = results[1];
            var diagResp = results[2];

            if (detailsResp.ok && detailsResp.session) {
                state.voiceLab.selectedSessionDetails = detailsResp.session;
            }
            if (turnsResp.ok && turnsResp.turns) {
                state.voiceLab.selectedSessionTurns = turnsResp.turns;
            }
            if (diagResp && diagResp.ok) {
                state.voiceLab.selectedSessionDiagnostics = diagResp;
            }
            state.voiceLab.sessionDetailsLoading = false;
            renderApp();
        })
        .catch(function (err) {
            console.error('[VTID-01218B] Error fetching session details:', err);
            state.voiceLab.sessionDetailsLoading = false;
            renderApp();
        });
}

/**
 * VTID-01218B: Start auto-refresh polling for Voice LAB sessions
 */
function startVoiceLabAutoRefresh() {
    if (state.voiceLab.autoRefreshIntervalId) {
        return; // Already running
    }
    console.log('[VTID-01218B] Starting auto-refresh (2s interval)');
    state.voiceLab.autoRefreshIntervalId = setInterval(function () {
        // BOOTSTRAP-SIDEBAR-FLICKER-FIX: ORB Live is reachable from two paths
        // (Diagnostics → Voice Lab AND Assistant → ORB Live). The Diagnostics
        // path's renderVoiceLabView fires stopVoiceLabAutoRefresh when its
        // activeSubTab changes, but the Assistant path doesn't — so the
        // interval was orphaned and fetchVoiceLabSessionsSilent →
        // updateVoiceLabSessionsTable → renderApp() fired every 2s on every
        // other screen, resetting sidebar scroll and causing flicker.
        //
        // Now: only fetch when the ORB Live panel is actually in view. If
        // not, self-cancel so we don't keep firing.
        var onOrbLive =
            (state.currentModuleKey === 'diagnostics' && state.currentTab === 'voice-lab'
             && state.voiceLab.activeSubTab === 'orb-live')
            || (state.currentModuleKey === 'assistant' && state.currentTab === 'orb-live')
            // VTID-02856: Voice section's Orb LIVE tab uses the same auto-refresh.
            || (state.currentModuleKey === 'voice' && state.currentTab === 'orb-live'
                && state.voiceLab.activeSubTab === 'orb-live');

        if (onOrbLive && state.voiceLab.autoRefreshEnabled) {
            fetchVoiceLabSessionsSilent();
        } else if (!onOrbLive) {
            stopVoiceLabAutoRefresh();
        }
    }, 2000);
}

/**
 * VTID-01218B: Stop auto-refresh polling
 */
function stopVoiceLabAutoRefresh() {
    if (state.voiceLab.autoRefreshIntervalId) {
        console.log('[VTID-01218B] Stopping auto-refresh');
        clearInterval(state.voiceLab.autoRefreshIntervalId);
        state.voiceLab.autoRefreshIntervalId = null;
    }
}

/**
 * VTID-01218B: Silent fetch (no loading state, for auto-refresh)
 */
function fetchVoiceLabSessionsSilent() {
    fetch('/api/v1/voice-lab/live/sessions')
        .then(function (resp) {
            if (!resp.ok) throw new Error('Failed to fetch sessions');
            return resp.json();
        })
        .then(function (data) {
            var freshSessions = (data.sessions || []).map(function (s) {
                return {
                    sessionId: s.session_id,
                    connected: s.status === 'active',
                    startedAt: s.started_at,
                    endedAt: s.ended_at,
                    lastActivity: s.ended_at || s.started_at,
                    turnCount: s.turn_count,
                    durationMs: s.duration_ms,
                    lang: s.lang,
                    errorCount: s.error_count,
                    interruptedCount: s.interrupted_count,
                    userId: s.user_id,
                    userEmail: s.user_email,
                    userDisplayName: s.user_display_name,
                    userRole: s.user_role,
                    platform: s.platform
                };
            });
            // If user has loaded more pages, keep those and only replace the first page
            if (state.voiceLab.sessions.length > freshSessions.length) {
                var extra = state.voiceLab.sessions.slice(freshSessions.length);
                state.voiceLab.sessions = freshSessions.concat(extra);
            } else {
                state.voiceLab.sessions = freshSessions;
            }
            // Update DOM without full re-render to preserve scroll/focus
            updateVoiceLabSessionsTable();
        })
        .catch(function (err) {
            console.error('[VTID-01218B] Silent fetch error:', err);
        });
}

/**
 * VTID-01218B: Update sessions table without full re-render
 */
function updateVoiceLabSessionsTable() {
    // VTID-01218B: Don't re-render if a modal is open (login, etc.) - preserves input focus
    var modalOpen = document.querySelector('.auth-modal, .login-modal, .modal-overlay, .modal-backdrop');
    if (modalOpen) {
        return;
    }

    // Don't re-render if there's an active input focus
    var activeElement = document.activeElement;
    if (activeElement && (activeElement.tagName === 'INPUT' || activeElement.tagName === 'TEXTAREA')) {
        return;
    }

    var tbody = document.querySelector('.voice-lab-sessions-table tbody');
    if (!tbody) {
        // BOOTSTRAP-SIDEBAR-FLICKER-FIX: if the table isn't in the DOM we are
        // NOT on the ORB Live panel — just bail. The previous behaviour of
        // calling renderApp() here turned every orphaned interval tick into
        // a full re-render (sidebar scroll reset, flicker). If the user is
        // on the ORB Live panel and the table is genuinely still mounting,
        // the next tick (2s later) will find it.
        return;
    }

    // Only re-render if data actually changed (prevents scroll jump)
    var newFingerprint = state.voiceLab.sessions.map(function (s) {
        return s.sessionId + ':' + s.connected + ':' + s.turnCount + ':' + s.errorCount;
    }).join('|');
    if (newFingerprint === state.voiceLab._lastSessionsFingerprint) {
        return; // No change, skip re-render
    }
    state.voiceLab._lastSessionsFingerprint = newFingerprint;
    renderApp();
}

/**
 * VTID-0401: Sorts governance rules by the specified column.
 */
function sortGovernanceRules(column) {
    if (state.governanceRulesSortColumn === column) {
        // Toggle direction
        state.governanceRulesSortDirection = state.governanceRulesSortDirection === 'asc' ? 'desc' : 'asc';
    } else {
        state.governanceRulesSortColumn = column;
        state.governanceRulesSortDirection = 'asc';
    }
    renderApp();
}

/**
 * VTID-0401: Returns sorted and filtered governance rules.
 */
function getFilteredGovernanceRules() {
    let rules = [...state.governanceRules];

    // Apply search filter (VTID-0405: extended to include description)
    if (state.governanceRulesSearchQuery) {
        const query = state.governanceRulesSearchQuery.toLowerCase();
        rules = rules.filter(r =>
            r.id.toLowerCase().includes(query) ||
            r.title.toLowerCase().includes(query) ||
            (r.description && r.description.toLowerCase().includes(query))
        );
    }

    // Apply level filter
    if (state.governanceRulesLevelFilter) {
        rules = rules.filter(r => r.level === state.governanceRulesLevelFilter);
    }

    // Apply category filter
    if (state.governanceRulesCategoryFilter) {
        rules = rules.filter(r => r.domain === state.governanceRulesCategoryFilter);
    }

    // VTID-0405: Apply source filter (SYSTEM/CATALOG)
    if (state.governanceRulesSourceFilter) {
        rules = rules.filter(r => r.source === state.governanceRulesSourceFilter);
    }

    // Apply sorting
    const col = state.governanceRulesSortColumn;
    const dir = state.governanceRulesSortDirection === 'asc' ? 1 : -1;

    rules.sort((a, b) => {
        let aVal = a[col] || '';
        let bVal = b[col] || '';
        if (typeof aVal === 'string') aVal = aVal.toLowerCase();
        if (typeof bVal === 'string') bVal = bVal.toLowerCase();
        if (aVal < bVal) return -1 * dir;
        if (aVal > bVal) return 1 * dir;
        return 0;
    });

    return rules;
}

/**
 * VTID-0401: Renders the Governance Rules catalog view.
 */
function renderGovernanceRulesView() {
    const container = document.createElement('div');
    container.className = 'governance-rules-container';

    // Auto-fetch governance rules if not loaded and not currently loading
    if (state.governanceRules.length === 0 && !state.governanceRulesLoading && !state.governanceRulesError) {
        fetchGovernanceRules();
    }

    // Toolbar
    const toolbar = document.createElement('div');
    toolbar.className = 'governance-rules-toolbar';

    // Search input
    const search = document.createElement('input');
    search.className = 'search-field governance-rules-search';
    search.placeholder = 'Search rules by ID or title...';
    search.value = state.governanceRulesSearchQuery;
    search.oninput = (e) => {
        state.governanceRulesSearchQuery = e.target.value;
        renderApp();
    };
    toolbar.appendChild(search);

    // Level filter - static options per VTID-0401-B spec
    const levelSelect = document.createElement('select');
    levelSelect.className = 'form-control governance-filter-select';
    levelSelect.setAttribute('autocomplete', 'off');
    levelSelect.setAttribute('data-lpignore', 'true'); // LastPass ignore
    levelSelect.name = 'governance-level-filter-' + Date.now(); // Unique name prevents autofill
    levelSelect.innerHTML = '<option value="">All Levels</option>' +
        '<option value="L1">L1 (Critical)</option>' +
        '<option value="L2">L2 (Standard)</option>' +
        '<option value="L3">L3 (Structural)</option>' +
        '<option value="L4">L4 (Autonomy / Agents)</option>';
    // Set value based on state - empty string means "All Levels"
    levelSelect.value = state.governanceRulesLevelFilter || '';
    levelSelect.onchange = (e) => {
        state.governanceRulesLevelFilter = e.target.value;
        renderApp();
    };
    toolbar.appendChild(levelSelect);

    // Category/Domain filter - static options per VTID-0401-B spec
    // Using 6 canonical categories from specs/governance/rules.json
    const categorySelect = document.createElement('select');
    categorySelect.className = 'form-control governance-filter-select';
    categorySelect.setAttribute('autocomplete', 'off');
    categorySelect.setAttribute('data-lpignore', 'true'); // LastPass ignore
    categorySelect.name = 'governance-category-filter-' + Date.now(); // Unique name prevents autofill
    categorySelect.innerHTML = '<option value="">All Categories</option>' +
        '<option value="MIGRATION">Migration Governance</option>' +
        '<option value="FRONTEND">Frontend Governance</option>' +
        '<option value="CICD">CI/CD Governance</option>' +
        '<option value="DB">Database Governance</option>' +
        '<option value="AGENT">Agent Governance</option>' +
        '<option value="API">API Governance</option>';
    // Set value based on state - empty string means "All Categories"
    categorySelect.value = state.governanceRulesCategoryFilter || '';
    categorySelect.onchange = (e) => {
        state.governanceRulesCategoryFilter = e.target.value;
        renderApp();
    };
    toolbar.appendChild(categorySelect);

    // VTID-0405: Source/Family filter (SYSTEM vs CATALOG)
    const sourceSelect = document.createElement('select');
    sourceSelect.className = 'form-control governance-filter-select';
    sourceSelect.setAttribute('autocomplete', 'off');
    sourceSelect.setAttribute('data-lpignore', 'true');
    sourceSelect.name = 'governance-source-filter-' + Date.now();
    sourceSelect.innerHTML = '<option value="">All Sources</option>' +
        '<option value="SYSTEM">System Rules</option>' +
        '<option value="CATALOG">Catalog Rules</option>';
    sourceSelect.value = state.governanceRulesSourceFilter || '';
    sourceSelect.onchange = (e) => {
        state.governanceRulesSourceFilter = e.target.value;
        renderApp();
    };
    toolbar.appendChild(sourceSelect);

    // Spacer
    const spacer = document.createElement('div');
    spacer.className = 'spacer';
    toolbar.appendChild(spacer);

    // Rule count
    const filteredRules = getFilteredGovernanceRules();
    const countLabel = document.createElement('span');
    countLabel.className = 'governance-rules-count';
    countLabel.textContent = filteredRules.length + ' of ' + state.governanceRules.length + ' rules';
    toolbar.appendChild(countLabel);

    // SPEC-01: Per-view refresh buttons removed - use global refresh icon in header

    container.appendChild(toolbar);

    // Loading state
    if (state.governanceRulesLoading) {
        const loading = document.createElement('div');
        loading.className = 'governance-rules-loading';
        loading.innerHTML = '<div class="skeleton-table">' +
            '<div class="skeleton-row"></div>'.repeat(10) +
            '</div>';
        container.appendChild(loading);
        return container;
    }

    // Error state
    if (state.governanceRulesError) {
        const errorDiv = document.createElement('div');
        errorDiv.className = 'governance-rules-error';
        errorDiv.innerHTML = '<span class="error-icon">⚠</span> Error loading rules: ' + state.governanceRulesError;
        container.appendChild(errorDiv);
        return container;
    }

    // Table
    const tableWrapper = document.createElement('div');
    tableWrapper.className = 'governance-rules-table-wrapper';

    const table = document.createElement('table');
    table.className = 'governance-rules-table';

    // Table header
    const thead = document.createElement('thead');
    const headerRow = document.createElement('tr');

    const columns = [
        { key: 'id', label: 'Rule ID', sortable: true },
        { key: 'level', label: 'Level', sortable: true },
        { key: 'domain', label: 'Domain', sortable: true },
        { key: 'title', label: 'Title', sortable: true },
        { key: 'status', label: 'Status', sortable: true },
        { key: 'vtids', label: 'VTIDs', sortable: false },
        { key: 'updated_at', label: 'Updated', sortable: true }
    ];

    columns.forEach(col => {
        const th = document.createElement('th');
        th.className = col.sortable ? 'sortable' : '';
        if (col.sortable) {
            th.onclick = () => sortGovernanceRules(col.key);
            const sortIndicator = state.governanceRulesSortColumn === col.key
                ? (state.governanceRulesSortDirection === 'asc' ? ' ↑' : ' ↓')
                : '';
            th.textContent = col.label + sortIndicator;
        } else {
            th.textContent = col.label;
        }
        headerRow.appendChild(th);
    });

    thead.appendChild(headerRow);
    table.appendChild(thead);

    // Table body
    const tbody = document.createElement('tbody');

    filteredRules.forEach(rule => {
        const row = document.createElement('tr');
        row.className = 'governance-rule-row';
        row.onclick = () => {
            state.selectedGovernanceRule = rule;
            renderApp();
        };

        // Rule ID
        const idCell = document.createElement('td');
        idCell.className = 'rule-id-cell';
        idCell.textContent = rule.id;
        row.appendChild(idCell);

        // Level with badge
        const levelCell = document.createElement('td');
        const levelBadge = document.createElement('span');
        levelBadge.className = 'level-badge level-' + rule.level.toLowerCase();
        levelBadge.textContent = rule.level;
        levelCell.appendChild(levelBadge);
        row.appendChild(levelCell);

        // Domain
        const domainCell = document.createElement('td');
        domainCell.className = 'domain-cell';
        domainCell.textContent = rule.domain;
        row.appendChild(domainCell);

        // Title
        const titleCell = document.createElement('td');
        titleCell.className = 'title-cell';
        titleCell.textContent = rule.title;
        row.appendChild(titleCell);

        // Status with badge
        const statusCell = document.createElement('td');
        const statusBadge = document.createElement('span');
        statusBadge.className = 'status-badge status-' + rule.status.toLowerCase();
        statusBadge.textContent = rule.status.charAt(0).toUpperCase() + rule.status.slice(1);
        statusCell.appendChild(statusBadge);
        row.appendChild(statusCell);

        // VTIDs
        const vtidsCell = document.createElement('td');
        vtidsCell.className = 'vtids-cell';
        if (rule.vtids && rule.vtids.length > 0) {
            vtidsCell.innerHTML = rule.vtids.slice(0, 2).map(v =>
                '<span class="vtid-chip">' + v + '</span>'
            ).join('');
            if (rule.vtids.length > 2) {
                vtidsCell.innerHTML += '<span class="vtid-more">+' + (rule.vtids.length - 2) + '</span>';
            }
        } else {
            vtidsCell.textContent = '-';
        }
        row.appendChild(vtidsCell);

        // Updated
        const updatedCell = document.createElement('td');
        updatedCell.className = 'updated-cell';
        updatedCell.textContent = formatRelativeDate(rule.updated_at);
        row.appendChild(updatedCell);

        tbody.appendChild(row);
    });

    table.appendChild(tbody);
    tableWrapper.appendChild(table);
    container.appendChild(tableWrapper);

    return container;
}

/**
 * VTID-0401: Renders the rule detail sheet/drawer.
 */
function renderGovernanceRuleDetailDrawer() {
    const drawer = document.createElement('div');
    drawer.className = 'governance-rule-drawer ' + (state.selectedGovernanceRule ? 'open' : '');

    if (!state.selectedGovernanceRule) return drawer;

    const rule = state.selectedGovernanceRule;

    // Header
    const header = document.createElement('div');
    header.className = 'drawer-header';

    const title = document.createElement('h2');
    title.className = 'drawer-title-text';
    title.textContent = rule.id;
    header.appendChild(title);

    const closeBtn = document.createElement('button');
    closeBtn.className = 'drawer-close-btn';
    closeBtn.innerHTML = '&times;';
    closeBtn.onclick = () => {
        state.selectedGovernanceRule = null;
        renderApp();
    };
    header.appendChild(closeBtn);

    drawer.appendChild(header);

    // Content
    const content = document.createElement('div');
    content.className = 'drawer-content';
    content.dataset.scrollRetain = 'true';
    content.dataset.scrollKey = 'governance-rule-drawer';

    // Rule metadata
    const metaSection = document.createElement('div');
    metaSection.className = 'rule-detail-meta';

    const levelBadge = document.createElement('span');
    levelBadge.className = 'level-badge level-' + rule.level.toLowerCase();
    levelBadge.textContent = rule.level;
    metaSection.appendChild(levelBadge);

    const statusBadge = document.createElement('span');
    statusBadge.className = 'status-badge status-' + rule.status.toLowerCase();
    statusBadge.textContent = rule.status.charAt(0).toUpperCase() + rule.status.slice(1);
    metaSection.appendChild(statusBadge);

    const domainBadge = document.createElement('span');
    domainBadge.className = 'domain-badge';
    domainBadge.textContent = rule.domain;
    metaSection.appendChild(domainBadge);

    content.appendChild(metaSection);

    // Title
    const titleSection = document.createElement('div');
    titleSection.className = 'rule-detail-section';
    titleSection.innerHTML = '<h3>Title</h3><p>' + escapeHtml(rule.title) + '</p>';
    content.appendChild(titleSection);

    // Description
    const descSection = document.createElement('div');
    descSection.className = 'rule-detail-section';
    descSection.innerHTML = '<h3>Description</h3><p>' + escapeHtml(rule.description) + '</p>';
    content.appendChild(descSection);

    // Category
    const categorySection = document.createElement('div');
    categorySection.className = 'rule-detail-section';
    categorySection.innerHTML = '<h3>Category</h3><p>' + escapeHtml(rule.category) + '</p>';
    content.appendChild(categorySection);

    // VTID-0405: Source/Family (SYSTEM vs CATALOG)
    const sourceSection = document.createElement('div');
    sourceSection.className = 'rule-detail-section';
    const sourceValue = rule.source || 'CATALOG';
    const sourceLabel = sourceValue === 'SYSTEM' ? 'System Rule' : 'Catalog Rule';
    sourceSection.innerHTML = '<h3>Source</h3><p><span class="source-badge source-' + sourceValue.toLowerCase() + '">' + sourceLabel + '</span></p>';
    content.appendChild(sourceSection);

    // VTID-0405: Enforcement Semantics based on level
    const enforcementSemanticsSection = document.createElement('div');
    enforcementSemanticsSection.className = 'rule-detail-section';
    let enforcementSemantics = '';
    let enforcementClass = '';
    switch (rule.level) {
        case 'L1':
            enforcementSemantics = 'Hard block — always denies. This rule cannot be bypassed and will block any violating action.';
            enforcementClass = 'enforcement-hard';
            break;
        case 'L2':
            enforcementSemantics = 'Soft block — denies unless override (future). This rule blocks by default but may support authorized overrides.';
            enforcementClass = 'enforcement-soft';
            break;
        case 'L3':
            enforcementSemantics = 'Informational — not blocking. This rule logs violations but does not prevent actions.';
            enforcementClass = 'enforcement-info';
            break;
        case 'L4':
            enforcementSemantics = 'Informational — not blocking. Advisory rule for agent autonomy guidance.';
            enforcementClass = 'enforcement-info';
            break;
        default:
            enforcementSemantics = 'Unknown enforcement level.';
            enforcementClass = 'enforcement-info';
    }
    enforcementSemanticsSection.innerHTML = '<h3>Enforcement Semantics</h3><div class="enforcement-semantics ' + enforcementClass + '">' + enforcementSemantics + '</div>';
    content.appendChild(enforcementSemanticsSection);

    // VTIDs
    if (rule.vtids && rule.vtids.length > 0) {
        const vtidsSection = document.createElement('div');
        vtidsSection.className = 'rule-detail-section';
        vtidsSection.innerHTML = '<h3>Linked VTIDs</h3><div class="vtid-chips">' +
            rule.vtids.map(v => '<span class="vtid-chip">' + escapeHtml(v) + '</span>').join('') +
            '</div>';
        content.appendChild(vtidsSection);
    }

    // Sources
    if (rule.sources && rule.sources.length > 0) {
        const sourcesSection = document.createElement('div');
        sourcesSection.className = 'rule-detail-section';
        sourcesSection.innerHTML = '<h3>Sources</h3><ul class="sources-list">' +
            rule.sources.map(s => '<li><code>' + escapeHtml(s) + '</code></li>').join('') +
            '</ul>';
        content.appendChild(sourcesSection);
    }

    // Enforcement
    if (rule.enforcement && rule.enforcement.length > 0) {
        const enforcementSection = document.createElement('div');
        enforcementSection.className = 'rule-detail-section';
        enforcementSection.innerHTML = '<h3>Enforcement</h3><div class="enforcement-chips">' +
            rule.enforcement.map(e => '<span class="enforcement-chip">' + escapeHtml(e) + '</span>').join('') +
            '</div>';
        content.appendChild(enforcementSection);
    }

    // VTID-0405: Created At
    const createdSection = document.createElement('div');
    createdSection.className = 'rule-detail-section';
    createdSection.innerHTML = '<h3>Created</h3><p>' + formatRelativeDate(rule.created_at) + '</p>';
    content.appendChild(createdSection);

    // Updated
    const updatedSection = document.createElement('div');
    updatedSection.className = 'rule-detail-section';
    updatedSection.innerHTML = '<h3>Last Updated</h3><p>' + formatRelativeDate(rule.updated_at) + '</p>';
    content.appendChild(updatedSection);

    drawer.appendChild(content);

    return drawer;
}

/**
 * Helper: Format relative date.
 */
function formatRelativeDate(dateStr) {
    if (!dateStr) return '-';
    try {
        const date = new Date(dateStr);
        const now = new Date();
        const diffMs = now - date;
        const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

        if (diffDays === 0) return 'Today';
        if (diffDays === 1) return 'Yesterday';
        if (diffDays < 7) return diffDays + ' days ago';
        if (diffDays < 30) return Math.floor(diffDays / 7) + ' weeks ago';
        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    } catch (e) {
        return dateStr;
    }
}

/**
 * Helper: Escape HTML to prevent XSS.
 */
function escapeHtml(str) {
    if (!str) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#039;');
}

// --- VTID-0406: Governance Evaluations Viewer (OASIS Integration) ---

/**
 * VTID-0406: Fetches governance evaluation events from OASIS.
 * Populates state.governanceEvaluations with the evaluation data.
 */
async function fetchGovernanceEvaluations() {
    state.governanceEvaluationsLoading = true;
    state.governanceEvaluationsFetched = true;
    renderApp();

    try {
        const response = await fetch('/api/v1/governance/evaluations');
        const json = await response.json();

        if (json.ok && json.data) {
            state.governanceEvaluations = json.data;
            state.governanceEvaluationsError = null;
            console.log('[VTID-0406] Governance evaluations loaded:', json.count, 'evaluations');
        } else {
            throw new Error(json.error || 'Failed to load governance evaluations');
        }
    } catch (error) {
        console.error('[VTID-0406] Failed to fetch governance evaluations:', error);
        state.governanceEvaluationsError = error.message;
        state.governanceEvaluations = [];
    } finally {
        state.governanceEvaluationsLoading = false;
        renderApp();
    }
}

/**
 * VTID-0406: Returns filtered governance evaluations based on result filter.
 */
function getFilteredGovernanceEvaluations() {
    var evals = state.governanceEvaluations.slice();

    // Filter by result (allow/deny)
    if (state.governanceEvaluationsResultFilter) {
        var isAllow = state.governanceEvaluationsResultFilter === 'allow';
        evals = evals.filter(function (ev) { return ev.allow === isAllow; });
    }

    return evals;
}

/**
 * VTID-0406: Renders the Governance Evaluations viewer.
 */
function renderGovernanceEvaluationsView() {
    var container = document.createElement('div');
    container.className = 'gov-evals-container';

    // Auto-fetch evaluations if not yet fetched and not currently loading
    if (!state.governanceEvaluationsFetched && !state.governanceEvaluationsLoading) {
        fetchGovernanceEvaluations();
    }

    // Toolbar
    var toolbar = document.createElement('div');
    toolbar.className = 'gov-evals-toolbar';

    // Result filter
    var resultSelect = document.createElement('select');
    resultSelect.className = 'form-control governance-filter-select';
    resultSelect.autocomplete = 'off';
    resultSelect.name = 'gov-evals-result-filter-' + Date.now();
    resultSelect.innerHTML =
        '<option value="">All Results</option>' +
        '<option value="allow">Allow</option>' +
        '<option value="deny">Deny</option>';
    resultSelect.value = state.governanceEvaluationsResultFilter || '';
    resultSelect.onchange = function (e) {
        state.governanceEvaluationsResultFilter = e.target.value;
        renderApp();
    };
    toolbar.appendChild(resultSelect);

    // Spacer
    var spacer = document.createElement('div');
    spacer.className = 'spacer';
    toolbar.appendChild(spacer);

    // Count label
    var filteredEvals = getFilteredGovernanceEvaluations();
    var countLabel = document.createElement('span');
    countLabel.className = 'gov-evals-count';
    countLabel.textContent = filteredEvals.length + ' of ' + state.governanceEvaluations.length + ' evaluations';
    toolbar.appendChild(countLabel);

    // Refresh button
    // SPEC-01: Per-view refresh buttons removed - use global refresh icon in header

    container.appendChild(toolbar);

    // Loading state
    if (state.governanceEvaluationsLoading) {
        var loading = document.createElement('div');
        loading.className = 'gov-evals-loading';
        loading.innerHTML = '<div class="skeleton-table">' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '</div>';
        container.appendChild(loading);
        return container;
    }

    // Error state
    if (state.governanceEvaluationsError) {
        var errorDiv = document.createElement('div');
        errorDiv.className = 'gov-evals-error';
        errorDiv.innerHTML = '<span class="error-icon">⚠</span> Error loading evaluations: ' + state.governanceEvaluationsError;
        container.appendChild(errorDiv);
        return container;
    }

    // Empty state
    if (filteredEvals.length === 0) {
        var emptyDiv = document.createElement('div');
        emptyDiv.className = 'gov-evals-empty';
        emptyDiv.innerHTML = '<p>No governance evaluations found.</p>' +
            '<p class="gov-evals-empty-hint">Evaluations will appear here when the GovernanceEvaluator processes requests.</p>';
        container.appendChild(emptyDiv);
        return container;
    }

    // Table wrapper
    var tableWrapper = document.createElement('div');
    tableWrapper.className = 'gov-evals-table-wrapper';

    // Table
    var table = document.createElement('table');
    table.className = 'gov-evals-table';

    // Table header
    var thead = document.createElement('thead');
    var headerRow = document.createElement('tr');
    var headers = ['Timestamp', 'Action', 'Service', 'Env', 'Result', 'Violated Rules'];
    headers.forEach(function (headerText) {
        var th = document.createElement('th');
        th.textContent = headerText;
        headerRow.appendChild(th);
    });
    thead.appendChild(headerRow);
    table.appendChild(thead);

    // Table body
    var tbody = document.createElement('tbody');
    filteredEvals.forEach(function (evalItem) {
        var row = document.createElement('tr');
        row.className = 'gov-eval-row';

        // Timestamp
        var timestampTd = document.createElement('td');
        timestampTd.className = 'gov-eval-timestamp';
        timestampTd.textContent = formatEvalTimestamp(evalItem.created_at);
        row.appendChild(timestampTd);

        // Action
        var actionTd = document.createElement('td');
        actionTd.className = 'gov-eval-action';
        actionTd.textContent = evalItem.action;
        row.appendChild(actionTd);

        // Service
        var serviceTd = document.createElement('td');
        serviceTd.className = 'gov-eval-service';
        serviceTd.textContent = evalItem.service;
        row.appendChild(serviceTd);

        // Environment
        var envTd = document.createElement('td');
        envTd.className = 'gov-eval-env';
        envTd.textContent = evalItem.environment;
        row.appendChild(envTd);

        // Result (Allow/Deny)
        var resultTd = document.createElement('td');
        var resultBadge = document.createElement('span');
        resultBadge.className = evalItem.allow ? 'gov-eval-allow' : 'gov-eval-deny';
        resultBadge.textContent = evalItem.allow ? 'Allow' : 'Deny';
        resultTd.appendChild(resultBadge);
        row.appendChild(resultTd);

        // Violated Rules (chips)
        var rulesTd = document.createElement('td');
        rulesTd.className = 'gov-eval-rules';
        if (evalItem.violated_rules && evalItem.violated_rules.length > 0) {
            evalItem.violated_rules.forEach(function (rule) {
                var chip = document.createElement('span');
                chip.className = 'gov-rule-chip gov-rule-chip-' + rule.level.toLowerCase();
                chip.innerHTML = '<span class="gov-rule-chip-id">' + escapeHtml(rule.rule_id) + '</span>' +
                    '<span class="gov-rule-chip-level">' + rule.level + '</span>';
                chip.title = rule.domain + ' - ' + rule.level;
                // VTID-0406: Click chip to open Rule Detail Drawer from VTID-0405
                chip.onclick = function (e) {
                    e.stopPropagation();
                    openRuleDetailByCode(rule.rule_id);
                };
                rulesTd.appendChild(chip);
            });
        } else {
            rulesTd.innerHTML = '<span class="gov-eval-no-violations">—</span>';
        }
        row.appendChild(rulesTd);

        tbody.appendChild(row);
    });
    table.appendChild(tbody);
    tableWrapper.appendChild(table);
    container.appendChild(tableWrapper);

    return container;
}

/**
 * VTID-0406: Format timestamp for evaluation display.
 */
function formatEvalTimestamp(dateStr) {
    if (!dateStr) return '-';
    try {
        var date = new Date(dateStr);
        return date.toLocaleString('en-US', {
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit'
        });
    } catch (e) {
        return dateStr;
    }
}

/**
 * VTID-0406: Opens the Rule Detail Drawer for a specific rule code.
 * Links to VTID-0405 Rule Detail Drawer functionality.
 */
function openRuleDetailByCode(ruleCode) {
    // Find the rule in the loaded governance rules
    var rule = state.governanceRules.find(function (r) {
        return r.id === ruleCode;
    });

    if (rule) {
        state.selectedGovernanceRule = rule;
        renderApp();
    } else {
        // If rules aren't loaded, fetch them first then try again
        console.log('[VTID-0406] Rule not in cache, fetching rules first:', ruleCode);
        fetchGovernanceRules().then(function () {
            var foundRule = state.governanceRules.find(function (r) {
                return r.id === ruleCode;
            });
            if (foundRule) {
                state.selectedGovernanceRule = foundRule;
                renderApp();
            } else {
                console.warn('[VTID-0406] Rule not found:', ruleCode);
            }
        });
    }
}

// --- VTID-0408: Governance History Timeline ---

/**
 * VTID-0408: Fetches governance history events from OASIS.
 * Populates state.governanceHistory with the event data.
 */
async function fetchGovernanceHistory() {
    state.governanceHistory.loading = true;
    state.governanceHistory.fetched = true;
    renderApp();

    try {
        // Build query string from filters and pagination
        var params = new URLSearchParams();
        params.append('limit', state.governanceHistory.pagination.limit.toString());
        params.append('offset', state.governanceHistory.pagination.offset.toString());

        if (state.governanceHistory.filters.type !== 'all') {
            params.append('type', state.governanceHistory.filters.type);
        }
        if (state.governanceHistory.filters.level !== 'all') {
            params.append('level', state.governanceHistory.filters.level);
        }
        if (state.governanceHistory.filters.actor !== 'all') {
            params.append('actor', state.governanceHistory.filters.actor);
        }

        var response = await fetch('/api/v1/governance/history?' + params.toString());
        var json = await response.json();

        if (json.ok && json.events) {
            state.governanceHistory.items = json.events;
            state.governanceHistory.pagination.hasMore = json.pagination.has_more;
            state.governanceHistory.error = null;
            console.log('[VTID-0408] Governance history loaded:', json.events.length, 'events');
        } else {
            throw new Error(json.error || 'Failed to load governance history');
        }
    } catch (error) {
        console.warn('[VTID-0408] Governance history fetch error:', error);
        state.governanceHistory.error = error.message;
        state.governanceHistory.items = [];
    } finally {
        state.governanceHistory.loading = false;
        renderApp();
    }
}

/**
 * VTID-0408: Renders the Governance History viewer.
 */
function renderGovernanceHistoryView() {
    var container = document.createElement('div');
    container.className = 'gov-history-container';

    // Auto-fetch history if not yet fetched and not currently loading
    if (!state.governanceHistory.fetched && !state.governanceHistory.loading) {
        fetchGovernanceHistory();
    }

    // Toolbar with filters
    var toolbar = document.createElement('div');
    toolbar.className = 'gov-history-toolbar';

    // Event Type filter
    var typeSelect = document.createElement('select');
    typeSelect.className = 'form-control governance-filter-select';
    typeSelect.autocomplete = 'off';
    typeSelect.name = 'gov-history-type-filter-' + Date.now();
    typeSelect.innerHTML =
        '<option value="all">All Types</option>' +
        '<option value="governance.deploy.allowed">Deploy Allowed</option>' +
        '<option value="governance.deploy.blocked">Deploy Blocked</option>' +
        '<option value="governance.evaluate">Evaluate</option>' +
        '<option value="governance.rule.created">Rule Created</option>' +
        '<option value="governance.rule.updated">Rule Updated</option>';
    typeSelect.value = state.governanceHistory.filters.type;
    typeSelect.onchange = function (e) {
        state.governanceHistory.filters.type = e.target.value;
        state.governanceHistory.pagination.offset = 0;
        state.governanceHistory.fetched = false;
        fetchGovernanceHistory();
    };
    toolbar.appendChild(typeSelect);

    // Level filter
    var levelSelect = document.createElement('select');
    levelSelect.className = 'form-control governance-filter-select';
    levelSelect.autocomplete = 'off';
    levelSelect.name = 'gov-history-level-filter-' + Date.now();
    levelSelect.innerHTML =
        '<option value="all">All Levels</option>' +
        '<option value="L1">L1</option>' +
        '<option value="L2">L2</option>' +
        '<option value="L3">L3</option>' +
        '<option value="L4">L4</option>';
    levelSelect.value = state.governanceHistory.filters.level;
    levelSelect.onchange = function (e) {
        state.governanceHistory.filters.level = e.target.value;
        state.governanceHistory.pagination.offset = 0;
        state.governanceHistory.fetched = false;
        fetchGovernanceHistory();
    };
    toolbar.appendChild(levelSelect);

    // Actor filter
    var actorSelect = document.createElement('select');
    actorSelect.className = 'form-control governance-filter-select';
    actorSelect.autocomplete = 'off';
    actorSelect.name = 'gov-history-actor-filter-' + Date.now();
    actorSelect.innerHTML =
        '<option value="all">All Actors</option>' +
        '<option value="operator">Operator</option>' +
        '<option value="autopilot">Autopilot</option>' +
        '<option value="validator">Validator</option>' +
        '<option value="system">System</option>';
    actorSelect.value = state.governanceHistory.filters.actor;
    actorSelect.onchange = function (e) {
        state.governanceHistory.filters.actor = e.target.value;
        state.governanceHistory.pagination.offset = 0;
        state.governanceHistory.fetched = false;
        fetchGovernanceHistory();
    };
    toolbar.appendChild(actorSelect);

    // Spacer
    var spacer = document.createElement('div');
    spacer.className = 'spacer';
    toolbar.appendChild(spacer);

    // Count label
    var countLabel = document.createElement('span');
    countLabel.className = 'gov-history-count';
    countLabel.textContent = state.governanceHistory.items.length + ' events';
    toolbar.appendChild(countLabel);

    // Refresh button
    // SPEC-01: Per-view refresh buttons removed - use global refresh icon in header

    container.appendChild(toolbar);

    // Loading state
    if (state.governanceHistory.loading) {
        var loading = document.createElement('div');
        loading.className = 'gov-history-loading';
        loading.innerHTML = '<div class="skeleton-table">' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '</div>';
        container.appendChild(loading);
        return container;
    }

    // Error state
    if (state.governanceHistory.error) {
        var errorDiv = document.createElement('div');
        errorDiv.className = 'gov-history-error';
        errorDiv.innerHTML = '<span class="error-icon">⚠</span> Error loading history: ' + escapeHtml(state.governanceHistory.error);
        container.appendChild(errorDiv);
        return container;
    }

    // Empty state
    if (state.governanceHistory.items.length === 0) {
        var emptyDiv = document.createElement('div');
        emptyDiv.className = 'gov-history-empty';
        emptyDiv.innerHTML = '<p>No governance history events found.</p>' +
            '<p class="gov-history-empty-hint">Events will appear here as governance actions are performed.</p>';
        container.appendChild(emptyDiv);
        return container;
    }

    // Table wrapper
    var tableWrapper = document.createElement('div');
    tableWrapper.className = 'gov-history-table-wrapper';

    // Table
    var table = document.createElement('table');
    table.className = 'gov-history-table';

    // Table header
    var thead = document.createElement('thead');
    var headerRow = document.createElement('tr');
    var headers = ['Timestamp', 'Type', 'Level', 'Actor', 'Summary', ''];
    headers.forEach(function (headerText) {
        var th = document.createElement('th');
        th.textContent = headerText;
        headerRow.appendChild(th);
    });
    thead.appendChild(headerRow);
    table.appendChild(thead);

    // Table body
    var tbody = document.createElement('tbody');
    state.governanceHistory.items.forEach(function (event) {
        var row = document.createElement('tr');
        row.className = 'gov-history-row';
        row.tabIndex = 0;
        row.setAttribute('role', 'button');
        row.setAttribute('aria-label', 'View event details: ' + event.summary);

        // Timestamp
        var timestampTd = document.createElement('td');
        timestampTd.className = 'gov-history-timestamp';
        timestampTd.textContent = formatHistoryTimestamp(event.timestamp);
        row.appendChild(timestampTd);

        // Type (badge)
        var typeTd = document.createElement('td');
        var typeBadge = document.createElement('span');
        typeBadge.className = 'gov-history-type-badge ' + getHistoryTypeBadgeClass(event.type);
        typeBadge.textContent = formatHistoryType(event.type);
        typeTd.appendChild(typeBadge);
        row.appendChild(typeTd);

        // Level
        var levelTd = document.createElement('td');
        if (event.level) {
            var levelBadge = document.createElement('span');
            levelBadge.className = 'level-badge level-' + event.level.toLowerCase();
            levelBadge.textContent = event.level;
            levelTd.appendChild(levelBadge);
        } else {
            levelTd.innerHTML = '<span class="gov-history-no-level">—</span>';
        }
        row.appendChild(levelTd);

        // Actor
        var actorTd = document.createElement('td');
        actorTd.className = 'gov-history-actor';
        var actorBadge = document.createElement('span');
        actorBadge.className = 'gov-history-actor-badge gov-history-actor-' + event.actor;
        actorBadge.textContent = capitalizeFirst(event.actor);
        actorTd.appendChild(actorBadge);
        row.appendChild(actorTd);

        // Summary
        var summaryTd = document.createElement('td');
        summaryTd.className = 'gov-history-summary';
        summaryTd.textContent = event.summary;
        row.appendChild(summaryTd);

        // Details chevron
        var detailsTd = document.createElement('td');
        detailsTd.className = 'gov-history-details-cell';
        var chevron = document.createElement('span');
        chevron.className = 'gov-history-chevron';
        chevron.textContent = '›';
        detailsTd.appendChild(chevron);
        row.appendChild(detailsTd);

        // Click handler to open drawer
        row.onclick = function () {
            state.governanceHistory.selectedEvent = event;
            renderApp();
        };
        row.onkeydown = function (e) {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                state.governanceHistory.selectedEvent = event;
                renderApp();
            }
        };

        tbody.appendChild(row);
    });
    table.appendChild(tbody);
    tableWrapper.appendChild(table);
    container.appendChild(tableWrapper);

    // Load more button
    if (state.governanceHistory.pagination.hasMore) {
        var loadMoreBtn = document.createElement('button');
        loadMoreBtn.className = 'btn gov-history-load-more';
        loadMoreBtn.textContent = 'Load More';
        loadMoreBtn.onclick = function () {
            state.governanceHistory.pagination.offset += state.governanceHistory.pagination.limit;
            fetchGovernanceHistory();
        };
        container.appendChild(loadMoreBtn);
    }

    // History Event Drawer
    if (state.governanceHistory.selectedEvent) {
        container.appendChild(renderGovernanceHistoryDrawer(state.governanceHistory.selectedEvent));
    }

    return container;
}

/**
 * VTID-0408: Renders the History Event Drawer.
 */
function renderGovernanceHistoryDrawer(event) {
    var drawer = document.createElement('div');
    drawer.className = 'gov-history-drawer open';

    // Header
    var header = document.createElement('div');
    header.className = 'gov-history-drawer-header';

    var title = document.createElement('h2');
    title.className = 'gov-history-drawer-title';
    title.textContent = formatHistoryType(event.type);
    header.appendChild(title);

    var closeBtn = document.createElement('button');
    closeBtn.className = 'drawer-close-btn';
    closeBtn.innerHTML = '×';
    closeBtn.onclick = function () {
        state.governanceHistory.selectedEvent = null;
        renderApp();
    };
    header.appendChild(closeBtn);

    drawer.appendChild(header);

    // Drawer content
    var content = document.createElement('div');
    content.className = 'gov-history-drawer-content';
    content.dataset.scrollRetain = 'true';
    content.dataset.scrollKey = 'gov-history-drawer';

    // Timestamp
    var timestampSection = document.createElement('div');
    timestampSection.className = 'gov-history-drawer-section';
    timestampSection.innerHTML = '<h3>Timestamp</h3><p>' + formatHistoryTimestamp(event.timestamp) + '</p>';
    content.appendChild(timestampSection);

    // Meta badges (level, actor)
    var metaSection = document.createElement('div');
    metaSection.className = 'gov-history-drawer-meta';

    if (event.level) {
        var levelBadge = document.createElement('span');
        levelBadge.className = 'level-badge level-' + event.level.toLowerCase();
        levelBadge.textContent = event.level;
        metaSection.appendChild(levelBadge);
    }

    var actorBadge = document.createElement('span');
    actorBadge.className = 'gov-history-actor-badge gov-history-actor-' + event.actor;
    actorBadge.textContent = capitalizeFirst(event.actor);
    metaSection.appendChild(actorBadge);

    var typeBadge = document.createElement('span');
    typeBadge.className = 'gov-history-type-badge ' + getHistoryTypeBadgeClass(event.type);
    typeBadge.textContent = formatHistoryType(event.type);
    metaSection.appendChild(typeBadge);

    content.appendChild(metaSection);

    // Summary
    var summarySection = document.createElement('div');
    summarySection.className = 'gov-history-drawer-section';
    summarySection.innerHTML = '<h3>Summary</h3><p>' + escapeHtml(event.summary) + '</p>';
    content.appendChild(summarySection);

    // Rule IDs as chips (if present in details)
    if (event.details && event.details.violations && event.details.violations.length > 0) {
        var rulesSection = document.createElement('div');
        rulesSection.className = 'gov-history-drawer-section';
        rulesSection.innerHTML = '<h3>Violated Rules</h3>';

        var rulesContainer = document.createElement('div');
        rulesContainer.className = 'gov-history-rules-chips';

        event.details.violations.forEach(function (violation) {
            var chip = document.createElement('span');
            chip.className = 'gov-rule-chip gov-rule-chip-' + (violation.level || 'l2').toLowerCase();
            chip.innerHTML = '<span class="gov-rule-chip-id">' + escapeHtml(violation.rule_id) + '</span>' +
                '<span class="gov-rule-chip-level">' + (violation.level || 'L2') + '</span>';
            chip.title = violation.message || 'Click to view rule details';
            chip.onclick = function (e) {
                e.stopPropagation();
                openRuleDetailByCode(violation.rule_id);
            };
            rulesContainer.appendChild(chip);
        });

        rulesSection.appendChild(rulesContainer);
        content.appendChild(rulesSection);
    }

    // Service / VTID info
    if (event.details && (event.details.service || event.details.vtid)) {
        var contextSection = document.createElement('div');
        contextSection.className = 'gov-history-drawer-section';
        contextSection.innerHTML = '<h3>Context</h3>';

        var contextList = document.createElement('div');
        contextList.className = 'gov-history-context-list';

        if (event.details.vtid) {
            var vtidItem = document.createElement('div');
            vtidItem.className = 'gov-history-context-item';
            vtidItem.innerHTML = '<span class="label">VTID:</span><span class="value">' + escapeHtml(event.details.vtid) + '</span>';
            contextList.appendChild(vtidItem);
        }
        if (event.details.service) {
            var serviceItem = document.createElement('div');
            serviceItem.className = 'gov-history-context-item';
            serviceItem.innerHTML = '<span class="label">Service:</span><span class="value">' + escapeHtml(event.details.service) + '</span>';
            contextList.appendChild(serviceItem);
        }

        contextSection.appendChild(contextList);
        content.appendChild(contextSection);
    }

    // Raw JSON details
    var jsonSection = document.createElement('div');
    jsonSection.className = 'gov-history-drawer-section gov-history-json-section';
    jsonSection.innerHTML = '<h3>Raw Details</h3>';

    var jsonPre = document.createElement('pre');
    jsonPre.className = 'gov-history-json';
    jsonPre.textContent = JSON.stringify(event.details || {}, null, 2);
    jsonSection.appendChild(jsonPre);
    content.appendChild(jsonSection);

    drawer.appendChild(content);

    return drawer;
}

// --- VTID-0409: Governance Categories (Read-Only V1) ---

/**
 * VTID-0409: Fetches governance categories from the API.
 * Populates state.governanceCategories with category data including rules.
 */
async function fetchGovernanceCategories() {
    state.governanceCategories.loading = true;
    state.governanceCategories.fetched = true;
    state.governanceCategories.error = null;
    renderApp();

    try {
        var response = await fetch('/api/v1/governance/categories');
        var json = await response.json();

        if (json.ok && json.categories) {
            state.governanceCategories.items = json.categories;

            // Auto-select first category if none selected
            if (!state.governanceCategories.selectedCategoryId && json.categories.length > 0) {
                state.governanceCategories.selectedCategoryId = json.categories[0].id;
            }

            console.log('[VTID-0409] Governance categories loaded:', json.categories.length, 'categories');
        } else {
            throw new Error(json.error || 'Failed to load governance categories');
        }
    } catch (error) {
        console.warn('[VTID-0409] Governance categories fetch error:', error);
        state.governanceCategories.error = error.message;
        state.governanceCategories.items = [];
    } finally {
        state.governanceCategories.loading = false;
        renderApp();
    }
}

/**
 * VTID-0409: Renders the Governance Categories view.
 * Two-column layout: left = category list, right = rules table for selected category.
 */
function renderGovernanceCategoriesView() {
    var container = document.createElement('div');
    container.className = 'gov-categories-container';

    // Auto-fetch categories if not yet fetched and not currently loading
    if (!state.governanceCategories.fetched && !state.governanceCategories.loading) {
        fetchGovernanceCategories();
    }

    // Loading state
    if (state.governanceCategories.loading) {
        var loading = document.createElement('div');
        loading.className = 'gov-categories-loading';
        loading.innerHTML = '<div class="skeleton-table">' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '</div>';
        container.appendChild(loading);
        return container;
    }

    // Error state
    if (state.governanceCategories.error) {
        var errorDiv = document.createElement('div');
        errorDiv.className = 'gov-categories-error';
        errorDiv.innerHTML = '<span class="error-icon">⚠</span> Error loading categories: ' + escapeHtml(state.governanceCategories.error);
        container.appendChild(errorDiv);
        return container;
    }

    // Empty state
    if (state.governanceCategories.items.length === 0) {
        var emptyDiv = document.createElement('div');
        emptyDiv.className = 'gov-categories-empty';
        emptyDiv.innerHTML = '<p>No governance categories found.</p>' +
            '<p class="gov-categories-empty-hint">Categories will appear here as governance rules are added.</p>';
        container.appendChild(emptyDiv);
        return container;
    }

    // Two-column layout
    var layout = document.createElement('div');
    layout.className = 'gov-categories-layout';

    // Left column: category list
    var leftColumn = document.createElement('div');
    leftColumn.className = 'gov-categories-list';

    var selectedId = state.governanceCategories.selectedCategoryId;
    var selectedCategory = state.governanceCategories.items.find(function (c) {
        return c.id === selectedId;
    }) || state.governanceCategories.items[0];

    state.governanceCategories.items.forEach(function (cat) {
        var catBtn = document.createElement('button');
        catBtn.className = 'gov-category-item' + (cat.id === selectedCategory.id ? ' selected' : '');
        catBtn.setAttribute('role', 'option');
        catBtn.setAttribute('aria-selected', cat.id === selectedCategory.id ? 'true' : 'false');

        var labelDiv = document.createElement('div');
        labelDiv.className = 'gov-category-label';
        labelDiv.textContent = cat.label;
        catBtn.appendChild(labelDiv);

        var metaDiv = document.createElement('div');
        metaDiv.className = 'gov-category-meta';

        var countSpan = document.createElement('span');
        countSpan.className = 'gov-category-count';
        countSpan.textContent = cat.rule_count + ' rule' + (cat.rule_count !== 1 ? 's' : '');
        metaDiv.appendChild(countSpan);

        var levelsSpan = document.createElement('span');
        levelsSpan.className = 'gov-category-levels';
        levelsSpan.innerHTML =
            '<span class="lvl lvl-L1" title="L1 Critical">' + cat.levels.L1 + '</span>' +
            '<span class="lvl lvl-L2" title="L2 High">' + cat.levels.L2 + '</span>' +
            '<span class="lvl lvl-L3" title="L3 Medium">' + cat.levels.L3 + '</span>' +
            '<span class="lvl lvl-L4" title="L4 Low">' + cat.levels.L4 + '</span>';
        metaDiv.appendChild(levelsSpan);

        catBtn.appendChild(metaDiv);

        catBtn.onclick = function () {
            state.governanceCategories.selectedCategoryId = cat.id;
            renderApp();
        };

        leftColumn.appendChild(catBtn);
    });

    layout.appendChild(leftColumn);

    // Right column: rules table for selected category
    var rightColumn = document.createElement('div');
    rightColumn.className = 'gov-category-rules';

    // Category header
    var catHeader = document.createElement('div');
    catHeader.className = 'gov-category-header';

    var catTitle = document.createElement('h3');
    catTitle.className = 'gov-category-title';
    catTitle.textContent = selectedCategory.label;
    catHeader.appendChild(catTitle);

    var catCount = document.createElement('span');
    catCount.className = 'gov-category-rule-count';
    catCount.textContent = selectedCategory.rule_count + ' rule' + (selectedCategory.rule_count !== 1 ? 's' : '');
    catHeader.appendChild(catCount);

    rightColumn.appendChild(catHeader);

    // Rules table
    if (selectedCategory.rules && selectedCategory.rules.length > 0) {
        var tableWrapper = document.createElement('div');
        tableWrapper.className = 'gov-category-table-wrapper';

        var table = document.createElement('table');
        table.className = 'gov-category-rules-table';

        // Table header
        var thead = document.createElement('thead');
        thead.innerHTML =
            '<tr>' +
            '<th>Rule ID</th>' +
            '<th>Title</th>' +
            '<th>Level</th>' +
            '<th>Source</th>' +
            '<th></th>' +
            '</tr>';
        table.appendChild(thead);

        // Table body
        var tbody = document.createElement('tbody');
        selectedCategory.rules.forEach(function (rule) {
            var row = document.createElement('tr');
            row.className = 'gov-category-rule-row';
            row.tabIndex = 0;
            row.setAttribute('role', 'button');
            row.setAttribute('aria-label', 'View rule details: ' + rule.rule_id);

            // Rule ID
            var idCell = document.createElement('td');
            idCell.className = 'gov-rule-id';
            idCell.textContent = rule.rule_id;
            row.appendChild(idCell);

            // Title
            var titleCell = document.createElement('td');
            titleCell.className = 'gov-rule-title';
            titleCell.textContent = rule.title;
            row.appendChild(titleCell);

            // Level badge
            var levelCell = document.createElement('td');
            levelCell.className = 'gov-rule-level-cell';
            var levelBadge = document.createElement('span');
            levelBadge.className = 'gov-rule-level lvl-' + rule.level;
            levelBadge.textContent = rule.level;
            levelCell.appendChild(levelBadge);
            row.appendChild(levelCell);

            // Source badge
            var sourceCell = document.createElement('td');
            sourceCell.className = 'gov-rule-source-cell';
            var sourceBadge = document.createElement('span');
            sourceBadge.className = 'gov-rule-source source-' + rule.source.toLowerCase();
            sourceBadge.textContent = rule.source;
            sourceCell.appendChild(sourceBadge);
            row.appendChild(sourceCell);

            // Chevron
            var chevronCell = document.createElement('td');
            chevronCell.className = 'gov-rule-chevron';
            chevronCell.innerHTML = '›';
            row.appendChild(chevronCell);

            // Click handler to open rule drawer
            row.onclick = function () {
                openRuleDetailByCode(rule.rule_id);
            };
            row.onkeydown = function (e) {
                if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    openRuleDetailByCode(rule.rule_id);
                }
            };

            tbody.appendChild(row);
        });

        table.appendChild(tbody);
        tableWrapper.appendChild(table);
        rightColumn.appendChild(tableWrapper);
    } else {
        var noRules = document.createElement('div');
        noRules.className = 'gov-categories-empty';
        noRules.innerHTML = '<p>No rules in this category.</p>';
        rightColumn.appendChild(noRules);
    }

    layout.appendChild(rightColumn);
    container.appendChild(layout);

    return container;
}

// =============================================================================
// VTID-01181: Governance Controls - System Arming Panel
// =============================================================================

/**
 * VTID-01181: Fetch governance controls from API.
 */
async function fetchGovernanceControls() {
    state.governanceControls.loading = true;
    state.governanceControls.error = null;
    renderApp();

    try {
        var response = await fetch('/api/v1/governance/controls', {
            method: 'GET',
            headers: buildContextHeaders()
        });

        var json = await response.json();

        if (!response.ok || !json.ok) {
            throw new Error(json.error || json.message || 'Failed to fetch controls');
        }

        state.governanceControls.items = json.data || [];
        state.governanceControls.fetched = true;
        console.log('[VTID-01181] Governance controls loaded:', state.governanceControls.items.length);
    } catch (error) {
        console.error('[VTID-01181] Failed to fetch governance controls:', error);
        state.governanceControls.error = error.message;
        state.governanceControls.items = [];
    } finally {
        state.governanceControls.loading = false;
        renderApp();
    }
}

/**
 * VTID-01181: Fetch audit history for a specific control.
 */
async function fetchControlHistory(key) {
    state.governanceControls.historyLoading = true;
    state.governanceControls.historyError = null;
    state.governanceControls.historyItems = [];
    renderApp();

    try {
        var response = await fetch('/api/v1/governance/controls/' + encodeURIComponent(key) + '/history?limit=50', {
            method: 'GET',
            headers: buildContextHeaders()
        });

        var json = await response.json();

        if (!response.ok || !json.ok) {
            throw new Error(json.error || json.message || 'Failed to fetch history');
        }

        state.governanceControls.historyItems = json.data || [];
        console.log('[VTID-01181] Control history loaded:', state.governanceControls.historyItems.length, 'entries');
    } catch (error) {
        console.error('[VTID-01181] Failed to fetch control history:', error);
        state.governanceControls.historyError = error.message;
    } finally {
        state.governanceControls.historyLoading = false;
        renderApp();
    }
}

/**
 * VTID-01181: Enable a system control.
 */
async function enableControl(key, reason, durationMinutes) {
    state.governanceControls.actionLoading = true;
    state.governanceControls.actionError = null;
    renderApp();

    try {
        var response = await fetch('/api/v1/governance/controls/' + encodeURIComponent(key), {
            method: 'POST',
            headers: Object.assign({ 'Content-Type': 'application/json' }, buildContextHeaders()),
            body: JSON.stringify({
                enabled: true,
                reason: reason,
                duration_minutes: durationMinutes
            })
        });

        var json = await response.json();

        if (!response.ok || !json.ok) {
            throw new Error(json.error || json.message || 'Failed to enable control');
        }

        showToast('Control enabled: ' + key, 'success');
        state.governanceControls.showEnableModal = false;
        state.governanceControls.enableReason = '';
        state.governanceControls.enableDuration = 60;
        state.governanceControls.fetched = false; // Force re-fetch
        fetchGovernanceControls();
    } catch (error) {
        console.error('[VTID-01181] Failed to enable control:', error);
        state.governanceControls.actionError = error.message;
        showToast('Failed to enable control: ' + error.message, 'error');
    } finally {
        state.governanceControls.actionLoading = false;
        renderApp();
    }
}

/**
 * VTID-01181: Disable a system control.
 */
async function disableControl(key, reason) {
    state.governanceControls.actionLoading = true;
    state.governanceControls.actionError = null;
    renderApp();

    try {
        var response = await fetch('/api/v1/governance/controls/' + encodeURIComponent(key), {
            method: 'POST',
            headers: Object.assign({ 'Content-Type': 'application/json' }, buildContextHeaders()),
            body: JSON.stringify({
                enabled: false,
                reason: reason
            })
        });

        var json = await response.json();

        if (!response.ok || !json.ok) {
            throw new Error(json.error || json.message || 'Failed to disable control');
        }

        showToast('Control disabled: ' + key, 'success');
        state.governanceControls.showDisableModal = false;
        state.governanceControls.disableReason = '';
        state.governanceControls.fetched = false; // Force re-fetch
        fetchGovernanceControls();
    } catch (error) {
        console.error('[VTID-01181] Failed to disable control:', error);
        state.governanceControls.actionError = error.message;
        showToast('Failed to disable control: ' + error.message, 'error');
    } finally {
        state.governanceControls.actionLoading = false;
        renderApp();
    }
}

/**
 * VTID-01181: Format control key for display.
 */
function formatControlKey(key) {
    var keyMap = {
        'vtid_allocator_enabled': 'VTID Allocator'
    };
    return keyMap[key] || key.replace(/_/g, ' ').replace(/\b\w/g, function (l) { return l.toUpperCase(); });
}

/**
 * VTID-01181: Calculate time remaining until expiry.
 */
function getTimeRemaining(expiresAt) {
    if (!expiresAt) return null;
    var now = new Date();
    var expiry = new Date(expiresAt);
    var diffMs = expiry - now;
    if (diffMs <= 0) return 'Expired';
    var minutes = Math.floor(diffMs / 60000);
    var hours = Math.floor(minutes / 60);
    if (hours > 0) {
        return hours + 'h ' + (minutes % 60) + 'm remaining';
    }
    return minutes + 'm remaining';
}

/**
 * VTID-01181: Renders the Governance Controls view (System Controls).
 */
function renderGovernanceControlsView() {
    var container = document.createElement('div');
    container.className = 'gov-controls-container';

    // Auto-fetch controls if not yet fetched and not currently loading
    if (!state.governanceControls.fetched && !state.governanceControls.loading) {
        fetchGovernanceControls();
    }

    // Header section
    var header = document.createElement('div');
    header.className = 'gov-controls-header';

    var headerTitle = document.createElement('h2');
    headerTitle.className = 'gov-controls-title';
    headerTitle.textContent = 'System Controls';
    header.appendChild(headerTitle);

    var headerDesc = document.createElement('p');
    headerDesc.className = 'gov-controls-desc';
    headerDesc.textContent = 'Enable or disable high-risk system capabilities without redeploys. All changes are audited.';
    header.appendChild(headerDesc);

    container.appendChild(header);

    // Loading state
    if (state.governanceControls.loading) {
        var loading = document.createElement('div');
        loading.className = 'gov-controls-loading';
        loading.innerHTML = '<div class="skeleton-table">' +
            '<div class="skeleton-row"></div>' +
            '<div class="skeleton-row"></div>' +
            '</div>';
        container.appendChild(loading);
        return container;
    }

    // Error state
    if (state.governanceControls.error) {
        var errorDiv = document.createElement('div');
        errorDiv.className = 'gov-controls-error';
        errorDiv.innerHTML = '<span class="error-icon">!</span> Error loading controls: ' + escapeHtml(state.governanceControls.error);
        container.appendChild(errorDiv);
        return container;
    }

    // Empty state
    if (state.governanceControls.items.length === 0) {
        var emptyDiv = document.createElement('div');
        emptyDiv.className = 'gov-controls-empty';
        emptyDiv.innerHTML = '<p>No system controls configured.</p>' +
            '<p class="gov-controls-empty-hint">Controls will appear here as they are added to the system.</p>';
        container.appendChild(emptyDiv);
        return container;
    }

    // Controls cards
    var cardsContainer = document.createElement('div');
    cardsContainer.className = 'gov-controls-cards';

    state.governanceControls.items.forEach(function (control) {
        var card = renderControlCard(control);
        cardsContainer.appendChild(card);
    });

    container.appendChild(cardsContainer);

    // Enable modal
    if (state.governanceControls.showEnableModal) {
        container.appendChild(renderEnableModal());
    }

    // Disable modal
    if (state.governanceControls.showDisableModal) {
        container.appendChild(renderDisableModal());
    }

    // History drawer
    if (state.governanceControls.showHistoryDrawer) {
        container.appendChild(renderControlHistoryDrawer());
    }

    return container;
}

/**
 * VTID-01181: Render a single control card.
 */
function renderControlCard(control) {
    var card = document.createElement('div');
    card.className = 'gov-control-card';

    // Check if expired
    var isExpired = control.expires_at && new Date(control.expires_at) <= new Date();
    var effectiveEnabled = control.enabled && !isExpired;

    // Card header
    var cardHeader = document.createElement('div');
    cardHeader.className = 'gov-control-card-header';

    var controlTitle = document.createElement('h3');
    controlTitle.className = 'gov-control-title';
    controlTitle.textContent = formatControlKey(control.key);
    cardHeader.appendChild(controlTitle);

    // Status pill
    var statusPill = document.createElement('span');
    statusPill.className = 'gov-control-status ' + (effectiveEnabled ? 'status-enabled' : 'status-disabled');
    statusPill.textContent = effectiveEnabled ? 'ENABLED' : 'DISABLED';
    cardHeader.appendChild(statusPill);

    card.appendChild(cardHeader);

    // Card body
    var cardBody = document.createElement('div');
    cardBody.className = 'gov-control-card-body';

    // Expiry info (if enabled and has expiry)
    if (effectiveEnabled && control.expires_at) {
        var expiryDiv = document.createElement('div');
        expiryDiv.className = 'gov-control-expiry';
        var timeRemaining = getTimeRemaining(control.expires_at);
        expiryDiv.innerHTML = '<span class="expiry-icon">&#9200;</span> ' + escapeHtml(timeRemaining);
        cardBody.appendChild(expiryDiv);
    }

    // Reason (if present)
    if (control.reason) {
        var reasonDiv = document.createElement('div');
        reasonDiv.className = 'gov-control-reason';
        reasonDiv.innerHTML = '<strong>Reason:</strong> ' + escapeHtml(control.reason);
        cardBody.appendChild(reasonDiv);
    }

    // Last updated info
    if (control.updated_by || control.updated_at) {
        var updatedDiv = document.createElement('div');
        updatedDiv.className = 'gov-control-updated';
        var updatedText = 'Last updated';
        if (control.updated_by) {
            updatedText += ' by ' + escapeHtml(control.updated_by);
        }
        if (control.updated_at) {
            updatedText += ' at ' + formatHistoryTimestamp(control.updated_at);
        }
        updatedDiv.textContent = updatedText;
        cardBody.appendChild(updatedDiv);
    }

    card.appendChild(cardBody);

    // Card actions
    var cardActions = document.createElement('div');
    cardActions.className = 'gov-control-card-actions';

    // Toggle button (Enable/Disable)
    var toggleBtn = document.createElement('button');
    toggleBtn.className = 'gov-control-toggle-btn ' + (effectiveEnabled ? 'btn-disable' : 'btn-enable');
    toggleBtn.textContent = effectiveEnabled ? 'Disable' : 'Enable';
    toggleBtn.onclick = function () {
        state.governanceControls.selectedControlKey = control.key;
        if (effectiveEnabled) {
            state.governanceControls.showDisableModal = true;
        } else {
            state.governanceControls.showEnableModal = true;
        }
        renderApp();
    };
    cardActions.appendChild(toggleBtn);

    // View history link
    var historyLink = document.createElement('button');
    historyLink.className = 'gov-control-history-link';
    historyLink.textContent = 'View history';
    historyLink.onclick = function () {
        state.governanceControls.selectedControlKey = control.key;
        state.governanceControls.showHistoryDrawer = true;
        fetchControlHistory(control.key);
    };
    cardActions.appendChild(historyLink);

    card.appendChild(cardActions);

    return card;
}

/**
 * VTID-01181: Render the Enable modal.
 */
function renderEnableModal() {
    var overlay = document.createElement('div');
    overlay.className = 'modal-overlay';
    overlay.onclick = function (e) {
        if (e.target === overlay) {
            state.governanceControls.showEnableModal = false;
            renderApp();
        }
    };

    var modal = document.createElement('div');
    modal.className = 'gov-control-modal';

    var modalHeader = document.createElement('div');
    modalHeader.className = 'gov-control-modal-header';
    modalHeader.innerHTML = '<h3>Enable Control: ' + escapeHtml(formatControlKey(state.governanceControls.selectedControlKey)) + '</h3>';
    modal.appendChild(modalHeader);

    var modalBody = document.createElement('div');
    modalBody.className = 'gov-control-modal-body';

    // Warning message
    var warning = document.createElement('div');
    warning.className = 'gov-control-modal-warning';
    warning.innerHTML = '<span class="warning-icon">!</span> Enabling this control activates high-risk functionality. All changes are logged to the audit trail.';
    modalBody.appendChild(warning);

    // Reason input (required)
    var reasonLabel = document.createElement('label');
    reasonLabel.className = 'gov-control-modal-label';
    reasonLabel.textContent = 'Reason (required)';
    modalBody.appendChild(reasonLabel);

    var reasonInput = document.createElement('textarea');
    reasonInput.className = 'gov-control-modal-textarea';
    reasonInput.placeholder = 'Why are you enabling this control?';
    reasonInput.value = state.governanceControls.enableReason;
    reasonInput.oninput = function (e) {
        state.governanceControls.enableReason = e.target.value;
    };
    modalBody.appendChild(reasonInput);

    // Duration select (optional in dev)
    var durationLabel = document.createElement('label');
    durationLabel.className = 'gov-control-modal-label';
    durationLabel.textContent = 'Duration (optional)';
    modalBody.appendChild(durationLabel);

    var durationSelect = document.createElement('select');
    durationSelect.className = 'gov-control-modal-select';
    var durations = [
        { value: 0, label: 'No expiry (indefinite)' },
        { value: 15, label: '15 minutes' },
        { value: 60, label: '1 hour' },
        { value: 240, label: '4 hours' },
        { value: 480, label: '8 hours' },
        { value: 1440, label: '24 hours' }
    ];
    durations.forEach(function (d) {
        var opt = document.createElement('option');
        opt.value = d.value;
        opt.textContent = d.label;
        opt.selected = d.value === state.governanceControls.enableDuration;
        durationSelect.appendChild(opt);
    });
    durationSelect.onchange = function (e) {
        state.governanceControls.enableDuration = parseInt(e.target.value, 10);
    };
    modalBody.appendChild(durationSelect);

    // Error message
    if (state.governanceControls.actionError) {
        var errorDiv = document.createElement('div');
        errorDiv.className = 'gov-control-modal-error';
        errorDiv.textContent = state.governanceControls.actionError;
        modalBody.appendChild(errorDiv);
    }

    modal.appendChild(modalBody);

    // Modal footer
    var modalFooter = document.createElement('div');
    modalFooter.className = 'gov-control-modal-footer';

    var cancelBtn = document.createElement('button');
    cancelBtn.className = 'gov-control-modal-cancel';
    cancelBtn.textContent = 'Cancel';
    cancelBtn.onclick = function () {
        state.governanceControls.showEnableModal = false;
        state.governanceControls.enableReason = '';
        state.governanceControls.actionError = null;
        renderApp();
    };
    modalFooter.appendChild(cancelBtn);

    var confirmBtn = document.createElement('button');
    confirmBtn.className = 'gov-control-modal-confirm btn-enable';
    confirmBtn.textContent = state.governanceControls.actionLoading ? 'Enabling...' : 'Confirm Enable';
    confirmBtn.disabled = state.governanceControls.actionLoading || !state.governanceControls.enableReason.trim();
    confirmBtn.onclick = function () {
        if (state.governanceControls.enableReason.trim()) {
            enableControl(
                state.governanceControls.selectedControlKey,
                state.governanceControls.enableReason.trim(),
                state.governanceControls.enableDuration || null
            );
        }
    };
    modalFooter.appendChild(confirmBtn);

    modal.appendChild(modalFooter);
    overlay.appendChild(modal);

    return overlay;
}

