// ===========================================================================
// Docs: System Knowledge — read-only mirror of knowledge_docs (vitana_system)
// ===========================================================================
//
// Operator view of what the Vitana Assistant "knows about itself" (Book of the
// Vitana Index + other vitana_system docs). Editing happens in the tenant-admin
// Knowledge UI (Vitanaland → Admin → Knowledge → Documents, system scope).
// Endpoint: GET /api/v1/admin/system-kb/docs  (exafy-admin only)

function initSystemKbState() {
    if (state.systemKb) return;
    state.systemKb = {
        docsLoading: false,
        docsError: null,
        docs: null,
        filterPrefix: 'kb/vitana-system/index-book/',
        searchQ: '',
        selectedId: null,
        selectedDocLoading: false,
        selectedDoc: null,
        selectedDocError: null,
    };
}

async function fetchSystemKbDocs() {
    initSystemKbState();
    state.systemKb.docsLoading = true;
    state.systemKb.docsError = null;
    renderApp();

    try {
        const token = state.authToken;
        const qs = new URLSearchParams();
        if (state.systemKb.filterPrefix) qs.set('path_prefix', state.systemKb.filterPrefix);
        if (state.systemKb.searchQ) qs.set('q', state.systemKb.searchQ);

        const response = await fetch('/api/v1/admin/system-kb/docs?' + qs.toString(), {
            headers: token ? { Authorization: 'Bearer ' + token } : {},
        });
        if (!response.ok) {
            const data = await response.json().catch(() => ({}));
            throw new Error(data.error || 'HTTP ' + response.status);
        }
        const json = await response.json();
        state.systemKb.docs = json.documents || [];
    } catch (err) {
        console.error('[system-knowledge] list error:', err);
        state.systemKb.docsError = err.message;
        state.systemKb.docs = null;
    } finally {
        state.systemKb.docsLoading = false;
        renderApp();
    }
}

async function fetchSystemKbDoc(id) {
    initSystemKbState();
    state.systemKb.selectedId = id;
    state.systemKb.selectedDoc = null;
    state.systemKb.selectedDocLoading = true;
    state.systemKb.selectedDocError = null;
    renderApp();

    try {
        const token = state.authToken;
        const response = await fetch('/api/v1/admin/system-kb/docs/' + encodeURIComponent(id), {
            headers: token ? { Authorization: 'Bearer ' + token } : {},
        });
        if (!response.ok) {
            const data = await response.json().catch(() => ({}));
            throw new Error(data.error || 'HTTP ' + response.status);
        }
        const json = await response.json();
        state.systemKb.selectedDoc = json.document;
    } catch (err) {
        console.error('[system-knowledge] detail error:', err);
        state.systemKb.selectedDocError = err.message;
    } finally {
        state.systemKb.selectedDocLoading = false;
        renderApp();
    }
}

function renderDocsSystemKnowledgeView() {
    initSystemKbState();

    // Deep-link: ?doc=<id> preselects the doc after the list loads.
    try {
        var urlParams = new URLSearchParams(window.location.search);
        var deepDocId = urlParams.get('doc');
        if (deepDocId && state.systemKb.selectedId !== deepDocId) {
            fetchSystemKbDoc(deepDocId);
        }
    } catch (_) { /* ignore */ }

    var container = document.createElement('div');
    container.className = 'docs-container';
    container.style.padding = '1.5rem';

    var title = document.createElement('h2');
    title.textContent = 'System Knowledge';
    container.appendChild(title);

    var subtitle = document.createElement('p');
    subtitle.className = 'section-subtitle';
    subtitle.textContent =
        'Read-only view of the system-wide knowledge_docs table that grounds the Vitana Assistant (retrieval-router priority 100). Edits happen in the tenant Knowledge admin → Documents → Vitana Platform scope.';
    container.appendChild(subtitle);

    // Filters
    var toolbar = document.createElement('div');
    toolbar.className = 'docs-toolbar';
    toolbar.style.flexWrap = 'wrap';
    toolbar.style.gap = '0.5rem';

    var filters = [
        { key: 'kb/vitana-system/index-book/', label: 'Book of the Vitana Index' },
        { key: 'kb/vitana-system/', label: 'All vitana_system docs' },
        { key: '', label: 'All system KB docs' },
    ];
    filters.forEach(function (f) {
        var btn = document.createElement('button');
        btn.className = state.systemKb.filterPrefix === f.key ? 'btn role-btn-active' : 'btn';
        btn.textContent = f.label;
        btn.onclick = function () {
            state.systemKb.filterPrefix = f.key;
            state.systemKb.selectedId = null;
            state.systemKb.selectedDoc = null;
            fetchSystemKbDocs();
        };
        toolbar.appendChild(btn);
    });
    container.appendChild(toolbar);

    var searchRow = document.createElement('div');
    searchRow.style.margin = '0.75rem 0';
    var searchInput = document.createElement('input');
    searchInput.type = 'search';
    searchInput.placeholder = 'Search by title or path…';
    searchInput.value = state.systemKb.searchQ;
    searchInput.style.width = '100%';
    searchInput.style.padding = '0.5rem 0.75rem';
    searchInput.style.background = 'var(--bg-secondary, #1a1a1a)';
    searchInput.style.border = '1px solid var(--border-color, #333)';
    searchInput.style.color = 'var(--text-primary, #fff)';
    searchInput.style.borderRadius = '6px';
    var searchTimer = null;
    searchInput.oninput = function (e) {
        state.systemKb.searchQ = e.target.value;
        if (searchTimer) clearTimeout(searchTimer);
        searchTimer = setTimeout(fetchSystemKbDocs, 250);
    };
    searchRow.appendChild(searchInput);
    container.appendChild(searchRow);

    // Two-pane layout: list | viewer
    var panes = document.createElement('div');
    panes.style.display = 'grid';
    panes.style.gridTemplateColumns = 'minmax(260px, 1fr) 2fr';
    panes.style.gap = '1rem';
    panes.style.marginTop = '1rem';

    // Left: list
    var listPane = document.createElement('div');
    listPane.style.minWidth = '0';

    if (state.systemKb.docs === null && !state.systemKb.docsLoading && !state.systemKb.docsError) {
        fetchSystemKbDocs();
    }

    if (state.systemKb.docsLoading) {
        listPane.innerHTML = '<div class="placeholder-content">Loading system KB…</div>';
    } else if (state.systemKb.docsError) {
        listPane.innerHTML =
            '<div class="placeholder-content error-text">Error: ' +
            escapeHtml(state.systemKb.docsError) +
            '</div>';
    } else if (!state.systemKb.docs || state.systemKb.docs.length === 0) {
        listPane.innerHTML = '<div class="placeholder-content">No docs match this filter.</div>';
    } else {
        var ul = document.createElement('ul');
        ul.style.listStyle = 'none';
        ul.style.padding = '0';
        ul.style.margin = '0';
        ul.style.maxHeight = '65vh';
        ul.style.overflowY = 'auto';
        state.systemKb.docs.forEach(function (d) {
            var li = document.createElement('li');
            var btn = document.createElement('button');
            btn.className = state.systemKb.selectedId === d.id ? 'btn role-btn-active' : 'btn';
            btn.style.display = 'block';
            btn.style.width = '100%';
            btn.style.textAlign = 'left';
            btn.style.marginBottom = '0.25rem';
            btn.style.padding = '0.5rem 0.75rem';
            btn.onclick = function () {
                fetchSystemKbDoc(d.id);
            };
            var titleEl = document.createElement('div');
            titleEl.textContent = d.title;
            titleEl.style.fontWeight = '500';
            btn.appendChild(titleEl);
            var pathEl = document.createElement('div');
            pathEl.textContent = d.path;
            pathEl.style.fontSize = '0.75rem';
            pathEl.style.opacity = '0.7';
            pathEl.style.wordBreak = 'break-all';
            pathEl.style.marginTop = '0.15rem';
            btn.appendChild(pathEl);
            li.appendChild(btn);
            ul.appendChild(li);
        });
        listPane.appendChild(ul);
    }
    panes.appendChild(listPane);

    // Right: viewer
    var viewerPane = document.createElement('div');
    viewerPane.style.minWidth = '0';
    viewerPane.style.background = 'var(--bg-secondary, #1a1a1a)';
    viewerPane.style.border = '1px solid var(--border-color, #333)';
    viewerPane.style.borderRadius = '6px';
    viewerPane.style.padding = '1rem';
    viewerPane.style.maxHeight = '70vh';
    viewerPane.style.overflowY = 'auto';

    if (!state.systemKb.selectedId) {
        viewerPane.innerHTML =
            '<div class="placeholder-content">Pick a doc from the list to read it.</div>';
    } else if (state.systemKb.selectedDocLoading) {
        viewerPane.innerHTML = '<div class="placeholder-content">Loading…</div>';
    } else if (state.systemKb.selectedDocError) {
        viewerPane.innerHTML =
            '<div class="placeholder-content error-text">Error: ' +
            escapeHtml(state.systemKb.selectedDocError) +
            '</div>';
    } else if (state.systemKb.selectedDoc) {
        var doc = state.systemKb.selectedDoc;
        var headerRow = document.createElement('div');
        headerRow.style.display = 'flex';
        headerRow.style.alignItems = 'baseline';
        headerRow.style.justifyContent = 'space-between';
        headerRow.style.gap = '0.5rem';
        var h = document.createElement('h3');
        h.textContent = doc.title;
        h.style.margin = '0 0 0.25rem 0';
        headerRow.appendChild(h);
        var editLink = document.createElement('a');
        editLink.href =
            'https://vitanaland.com/admin/knowledge/documents?scope=system&doc=' +
            encodeURIComponent(doc.id);
        editLink.target = '_blank';
        editLink.rel = 'noopener noreferrer';
        editLink.textContent = 'Edit in Vitanaland →';
        editLink.style.fontSize = '0.75rem';
        editLink.style.whiteSpace = 'nowrap';
        headerRow.appendChild(editLink);
        viewerPane.appendChild(headerRow);
        var p = document.createElement('div');
        p.textContent = doc.path;
        p.style.fontSize = '0.75rem';
        p.style.opacity = '0.7';
        p.style.wordBreak = 'break-all';
        viewerPane.appendChild(p);
        if (doc.tags && doc.tags.length) {
            var tagsEl = document.createElement('div');
            tagsEl.style.margin = '0.5rem 0';
            doc.tags.forEach(function (t) {
                var tag = document.createElement('span');
                tag.textContent = t;
                tag.style.display = 'inline-block';
                tag.style.fontSize = '0.7rem';
                tag.style.padding = '0.15rem 0.4rem';
                tag.style.marginRight = '0.25rem';
                tag.style.background = 'var(--bg-tertiary, #222)';
                tag.style.borderRadius = '3px';
                tagsEl.appendChild(tag);
            });
            viewerPane.appendChild(tagsEl);
        }
        var pre = document.createElement('pre');
        pre.textContent = doc.content || '';
        pre.style.whiteSpace = 'pre-wrap';
        pre.style.wordBreak = 'break-word';
        pre.style.fontFamily = 'inherit';
        pre.style.fontSize = '0.85rem';
        pre.style.lineHeight = '1.5';
        pre.style.marginTop = '0.5rem';
        viewerPane.appendChild(pre);
        var meta = document.createElement('div');
        meta.style.fontSize = '0.7rem';
        meta.style.opacity = '0.6';
        meta.style.marginTop = '1rem';
        meta.textContent =
            (doc.word_count || 0) +
            ' words · updated ' +
            new Date(doc.updated_at).toLocaleString();
        viewerPane.appendChild(meta);
    }
    panes.appendChild(viewerPane);

    container.appendChild(panes);
    return container;
}

// ===========================================================================
// Docs > Manuals: per-tenant Instruction Manual catalog
// ===========================================================================
// Renders the Maxina Instruction Manual (and other tenant manuals as they
// are authored) as a 13-module tree on the left, chapter content on the
// right. Reads from /api/v1/admin/system-kb/docs?path_prefix=kb/instruction-manual/.
// Edits route to the System Knowledge tab where the existing editor lives.

const TENANT_MANUAL_TENANTS = ['maxina', 'alkalma', 'earthlinks', 'community'];
const MANUAL_MODULE_LABELS = {
    '00-concepts': '0. Foundational Concepts',
    '01-public': '1. Public & Onboarding',
    '02-home': '2. Home',
    '03-community': '3. Community',
    '04-discover': '4. Discover',
    '05-health': '5. Health',
    '06-inbox': '6. Inbox',
    '07-ai': '7. AI',
    '08-wallet': '8. Wallet',
    '09-sharing': '9. Sharing',
    '10-memory': '10. Memory',
    '11-settings': '11. Settings',
    '12-utility': '12. Utility',
    '13-overlays': '13. Overlays & Popups',
};

function initManualsState() {
    if (!state.manuals) {
        state.manuals = {
            tenant: 'maxina',
            docs: [],
            loading: false,
            selectedId: null,
            selectedDoc: null,
            error: null,
            // Tracks which tenants have been fetched in this session.
            // Used by renderDocsManualsView's "fetch on first render" guard
            // so we never auto-refetch — even when the result was empty or
            // errored — which would otherwise infinite-loop the renderer.
            fetchedFor: {},
        };
    } else if (!state.manuals.fetchedFor) {
        state.manuals.fetchedFor = {};
    }
}

async function fetchManualsForTenant(tenant) {
    // Mark this tenant as attempted BEFORE any await so a re-render during
    // the fetch never re-enters this function.
    state.manuals.fetchedFor[tenant] = true;
    state.manuals.loading = true;
    state.manuals.error = null;
    renderApp();
    try {
        const prefix = 'kb/instruction-manual/' + tenant + '/';
        const qs = new URLSearchParams({ path_prefix: prefix });
        const response = await fetch('/api/v1/admin/system-kb/docs?' + qs.toString(), {
            headers: state.authToken ? { Authorization: 'Bearer ' + state.authToken } : {},
            credentials: 'include',
        });
        if (!response.ok) {
            const errBody = await response.json().catch(() => ({}));
            throw new Error(errBody.error || ('HTTP ' + response.status));
        }
        const json = await response.json();
        state.manuals.docs = json.documents || json.docs || [];
    } catch (err) {
        console.error('[manuals] fetch error:', err);
        state.manuals.error = err && err.message ? err.message : String(err);
        state.manuals.docs = [];
    } finally {
        state.manuals.loading = false;
        renderApp();
    }
}

async function fetchManualDoc(id) {
    state.manuals.selectedId = id;
    state.manuals.selectedDoc = null;
    state.manuals.selectedDocError = null;
    renderApp();
    try {
        const response = await fetch('/api/v1/admin/system-kb/docs/' + encodeURIComponent(id), {
            headers: state.authToken ? { Authorization: 'Bearer ' + state.authToken } : {},
            credentials: 'include',
        });
        const body = await response.json().catch(() => ({}));
        if (!response.ok) {
            throw new Error(body.error || ('HTTP ' + response.status));
        }
        // The endpoint returns { ok: true, document: {...} } — unwrap.
        state.manuals.selectedDoc = body.document || body.doc || body;
    } catch (err) {
        console.error('[manuals] fetch doc error:', err);
        state.manuals.selectedDocError = err && err.message ? err.message : String(err);
    } finally {
        renderApp();
    }
}

// Tiny markdown renderer — handles front-matter strip, headings, bold,
// italics, inline code, links, ordered + unordered lists, and paragraphs.
// Builds DOM nodes (escaping text first) so we can render chapter content
// safely inline without pulling in a markdown library.
function renderManualMarkdown(md) {
    const frag = document.createDocumentFragment();
    if (typeof md !== 'string' || !md) return frag;

    // Strip front-matter between leading '---' lines.
    let body = md;
    if (body.startsWith('---\n')) {
        const end = body.indexOf('\n---\n', 4);
        if (end !== -1) body = body.slice(end + 5);
    }

    const escapeHtml = function (s) {
        return String(s).replace(/[&<>"']/g, function (c) {
            return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
        });
    };

    const inline = function (text) {
        var s = escapeHtml(text);
        s = s.replace(/`([^`]+)`/g, '<code>$1</code>');
        s = s.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
        s = s.replace(/\*([^*]+)\*/g, '<em>$1</em>');
        s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, function (_m, t, u) {
            return '<a href="' + escapeHtml(u) + '" target="_blank" rel="noopener">' + t + '</a>';
        });
        return s;
    };
    const setHtml = function (tag, html) {
        const el = document.createElement(tag);
        el.innerHTML = html;
        return el;
    };

    const lines = body.split('\n');
    let i = 0;
    while (i < lines.length) {
        const line = lines[i];
        if (!line.trim()) { i++; continue; }

        const h = line.match(/^(#{1,6})\s+(.*)$/);
        if (h) {
            const tag = 'h' + Math.min(h[1].length, 6);
            const el = setHtml(tag, inline(h[2]));
            el.style.marginTop = '1.25rem';
            el.style.marginBottom = '0.5rem';
            frag.appendChild(el);
            i++; continue;
        }

        if (/^\s*[-*]\s/.test(line)) {
            const ul = document.createElement('ul');
            ul.style.marginLeft = '1.25rem';
            while (i < lines.length && /^\s*[-*]\s/.test(lines[i])) {
                ul.appendChild(setHtml('li', inline(lines[i].replace(/^\s*[-*]\s+/, ''))));
                i++;
            }
            frag.appendChild(ul); continue;
        }

        if (/^\s*\d+\.\s/.test(line)) {
            const ol = document.createElement('ol');
            ol.style.marginLeft = '1.25rem';
            while (i < lines.length && /^\s*\d+\.\s/.test(lines[i])) {
                ol.appendChild(setHtml('li', inline(lines[i].replace(/^\s*\d+\.\s+/, ''))));
                i++;
            }
            frag.appendChild(ol); continue;
        }

        // Paragraph: collect consecutive non-blank, non-block lines
        const para = [];
        while (
            i < lines.length && lines[i].trim() &&
            !/^(#{1,6})\s/.test(lines[i]) &&
            !/^\s*[-*]\s/.test(lines[i]) &&
            !/^\s*\d+\.\s/.test(lines[i])
        ) {
            para.push(lines[i]); i++;
        }
        if (para.length) {
            const p = setHtml('p', inline(para.join(' ')));
            p.style.lineHeight = '1.55';
            p.style.marginBottom = '0.75rem';
            frag.appendChild(p);
        }
    }
    return frag;
}

function groupManualsByModule(docs) {
    const groups = {};
    Object.keys(MANUAL_MODULE_LABELS).forEach(function (k) { groups[k] = []; });
    docs.forEach(function (doc) {
        const path = doc.path || '';
        const m = path.match(/kb\/instruction-manual\/[^/]+\/([0-9]{2}-[a-z]+)\//);
        const moduleKey = m ? m[1] : '00-concepts';
        if (!groups[moduleKey]) groups[moduleKey] = [];
        groups[moduleKey].push(doc);
    });
    Object.keys(groups).forEach(function (k) {
        groups[k].sort(function (a, b) { return (a.path || '').localeCompare(b.path || ''); });
    });
    return groups;
}

function renderDocsManualsView() {
    initManualsState();
    // Fire the fetch only once per tenant per session. The previous condition
    // (!docs.length && !loading && !error) re-fired every render after an
    // empty/errored response, which infinite-looped the renderer and froze
    // the entire Command Hub.
    if (!state.manuals.fetchedFor[state.manuals.tenant] && !state.manuals.loading) {
        fetchManualsForTenant(state.manuals.tenant);
    }

    const container = document.createElement('div');
    container.className = 'docs-container';
    container.style.padding = '1.5rem';

    const title = document.createElement('h2');
    title.textContent = 'Tenant Instruction Manuals';
    container.appendChild(title);

    const subtitle = document.createElement('p');
    subtitle.className = 'section-subtitle';
    subtitle.textContent =
        'Per-tenant chapters teaching every screen and concept the AI assistant explains to community users. Maxina ships first; other tenants populate as their manuals are authored. Edits route to the System Knowledge tab.';
    container.appendChild(subtitle);

    // Tenant selector
    const tenantRow = document.createElement('div');
    tenantRow.style.cssText = 'display:flex;gap:0.5rem;align-items:center;margin:0.5rem 0 1rem;';
    const tenantLabel = document.createElement('span');
    tenantLabel.textContent = 'Tenant:';
    tenantLabel.style.cssText = 'opacity:0.7;font-size:0.85rem;';
    tenantRow.appendChild(tenantLabel);
    const tenantSelect = document.createElement('select');
    tenantSelect.style.cssText = 'padding:0.4rem 0.6rem;background:var(--bg-secondary,#1a1a1a);color:inherit;border:1px solid var(--border,#333);border-radius:4px;';
    TENANT_MANUAL_TENANTS.forEach(function (t) {
        const opt = document.createElement('option');
        opt.value = t;
        opt.textContent = t.charAt(0).toUpperCase() + t.slice(1);
        if (t === state.manuals.tenant) opt.selected = true;
        tenantSelect.appendChild(opt);
    });
    tenantSelect.onchange = function () {
        state.manuals.tenant = tenantSelect.value;
        state.manuals.docs = [];
        state.manuals.selectedId = null;
        state.manuals.selectedDoc = null;
        fetchManualsForTenant(state.manuals.tenant);
    };
    tenantRow.appendChild(tenantSelect);
    container.appendChild(tenantRow);

    if (state.manuals.loading) {
        const loading = document.createElement('div');
        loading.style.padding = '2rem';
        loading.textContent = 'Loading manual…';
        container.appendChild(loading);
        return container;
    }

    if (state.manuals.error) {
        const errEl = document.createElement('div');
        errEl.style.cssText = 'padding:1rem;color:#f88;background:rgba(255,100,100,0.1);border-radius:4px;';
        errEl.textContent = 'Could not load manual: ' + state.manuals.error;
        container.appendChild(errEl);
        return container;
    }

    if (!state.manuals.docs.length) {
        const empty = document.createElement('div');
        empty.style.cssText = 'padding:2rem;text-align:center;opacity:0.7;';
        empty.innerHTML =
            '<p><strong>The ' + state.manuals.tenant.charAt(0).toUpperCase() + state.manuals.tenant.slice(1) + ' manual has not been authored yet.</strong></p>' +
            '<p style="font-size:0.9rem;margin-top:0.5rem;">See the Maxina manual as a reference template. New tenant manuals live under <code>kb/instruction-manual/&lt;tenant&gt;/</code> and are seeded by the <code>build-instruction-manual-seed.mjs</code> script.</p>';
        container.appendChild(empty);
        return container;
    }

    const groups = groupManualsByModule(state.manuals.docs);

    const panes = document.createElement('div');
    panes.style.cssText = 'display:flex;gap:1rem;align-items:stretch;min-height:60vh;';

    const treePane = document.createElement('div');
    treePane.style.cssText = 'flex:0 0 320px;background:var(--bg-secondary,#1a1a1a);border-radius:6px;padding:0.75rem;overflow-y:auto;max-height:75vh;';
    Object.keys(MANUAL_MODULE_LABELS).forEach(function (moduleKey) {
        const docs = groups[moduleKey] || [];
        if (!docs.length) return;
        const group = document.createElement('details');
        group.open = moduleKey === '00-concepts';
        group.style.marginBottom = '0.5rem';
        const summary = document.createElement('summary');
        summary.style.cssText = 'cursor:pointer;font-weight:600;padding:0.3rem 0;';
        summary.textContent = MANUAL_MODULE_LABELS[moduleKey] + ' (' + docs.length + ')';
        group.appendChild(summary);
        docs.forEach(function (doc) {
            const link = document.createElement('a');
            link.href = '#';
            link.textContent = doc.title || doc.path;
            link.style.cssText = 'display:block;padding:0.25rem 0.5rem;font-size:0.85rem;color:inherit;text-decoration:none;border-radius:3px;';
            if (state.manuals.selectedId === doc.id) {
                link.style.background = 'var(--accent,#4a90e2)';
                link.style.color = '#fff';
            }
            link.onclick = function (ev) {
                ev.preventDefault();
                fetchManualDoc(doc.id);
            };
            group.appendChild(link);
        });
        treePane.appendChild(group);
    });
    panes.appendChild(treePane);

    const viewerPane = document.createElement('div');
    viewerPane.style.cssText = 'flex:1;background:var(--bg-secondary,#1a1a1a);border-radius:6px;padding:1.25rem 1.5rem;overflow-y:auto;max-height:75vh;';

    if (state.manuals.selectedDocError) {
        const errEl = document.createElement('div');
        errEl.style.cssText = 'padding:1rem;color:#f88;background:rgba(255,100,100,0.1);border-radius:4px;';
        errEl.textContent = 'Could not load chapter: ' + state.manuals.selectedDocError;
        viewerPane.appendChild(errEl);
    } else if (state.manuals.selectedId && !state.manuals.selectedDoc) {
        const loadingEl = document.createElement('div');
        loadingEl.style.cssText = 'padding:2rem;opacity:0.6;text-align:center;';
        loadingEl.textContent = 'Loading chapter…';
        viewerPane.appendChild(loadingEl);
    } else if (state.manuals.selectedDoc) {
        const doc = state.manuals.selectedDoc;

        // Title + small path/meta line at the top
        const docTitle = document.createElement('h2');
        docTitle.style.cssText = 'margin:0 0 0.25rem 0;font-size:1.4rem;';
        docTitle.textContent = doc.title || '(untitled)';
        viewerPane.appendChild(docTitle);

        const meta = document.createElement('div');
        meta.style.cssText = 'font-size:0.75rem;opacity:0.55;margin-bottom:1.25rem;font-family:monospace;';
        meta.textContent = doc.path || '';
        viewerPane.appendChild(meta);

        // Render markdown inline. Read-only by design — this surface lives next
        // to System Knowledge which owns editing; bouncing between tabs was the
        // wrong UX and the prior 'Edit in System Knowledge' link is removed.
        const article = document.createElement('div');
        article.className = 'manual-article';
        article.style.cssText = 'font-size:0.95rem;color:var(--text,#eaeaea);';
        article.appendChild(renderManualMarkdown(doc.content || ''));
        viewerPane.appendChild(article);
    } else {
        const placeholder = document.createElement('div');
        placeholder.style.cssText = 'padding:2rem;opacity:0.6;text-align:center;';
        placeholder.textContent = 'Select a chapter on the left to read it.';
        viewerPane.appendChild(placeholder);
    }
    panes.appendChild(viewerPane);

    container.appendChild(panes);
    return container;
}

// ===========================================================================
// Helper: Auto-add Load More to any container with tables/lists
// ===========================================================================

function autoAddLoadMore(container, stateKey) {
    // Find if container has a table or list
    var hasTable = container.querySelector('table.list-table');
    var hasList = container.querySelector('.sse-event-list, .error-list, .log-list');

    if (!hasTable && !hasList) return; // No paginated content

    // Initialize pagination state if not exists
    if (!state[stateKey]) return;
    if (!state[stateKey]._limit) state[stateKey]._limit = 50;
    if (!state[stateKey]._hasMore) state[stateKey]._hasMore = true; // Assume more data initially

    var currentCount = state[stateKey].items ? state[stateKey].items.length : 0;
    var limit = state[stateKey]._limit || 50;

    // If we got fewer items than requested, no more data
    if (currentCount < limit && state[stateKey].fetched) {
        state[stateKey]._hasMore = false;
    }

    var hasMore = state[stateKey]._hasMore;

    if (currentCount === 0) return; // No items to paginate

    // Create Load More button
    var btnContainer = document.createElement('div');
    btnContainer.style.display = 'flex';
    btnContainer.style.justifyContent = 'center';
    btnContainer.style.padding = '1.5rem 0';
    btnContainer.style.marginTop = '1rem';

    var btn = document.createElement('button');
    btn.className = 'btn btn-secondary btn-load-more';
    btn.textContent = hasMore ? 'Load More (' + currentCount + ' shown)' : 'Showing all ' + currentCount + ' items';
    btn.disabled = !hasMore || state[stateKey].loading;

    if (hasMore) {
        btn.onclick = function() {
            state[stateKey]._limit += 50;
            state[stateKey].fetched = false;
            renderApp();
        };
    }

    btnContainer.appendChild(btn);
    container.appendChild(btnContainer);
}

// --- Init ---

document.addEventListener('DOMContentLoaded', async () => {
    console.log('%c[BOOT] command-hub v2026-04-10-postlogin-boot-v2', 'color:#3b82f6;font-weight:bold;font-size:14px');
    console.log('App v4 starting...');
    try {
        // Init Router
        const route = getRouteFromPath(window.location.pathname);
        state.currentModuleKey = route.section;
        state.currentTab = route.tab;
        applyRouteSubtab(route);

        // If current path is not valid or is root, replace with calculated path
        const section = NAVIGATION_CONFIG.find(s => s.section === route.section);
        const tab = section ? section.tabs.find(t => t.key === route.tab) : null;
        if (tab && window.location.pathname !== tab.path) {
            history.replaceState(null, '', tab.path);
        }

        // VTID-01230: If no auth token, show auth gate immediately — do NOT load any data
        if (!state.authToken) {
            console.log('[VTID-01230] No auth token — showing auth gate');
            renderApp(); // Will render auth gate
            return;
        }

        renderApp();

        // VTID-01046: Unified Auth Boot Sequence
        // Synchronize identity and context before loading other data
        console.log('[VTID-01046] Booting Auth...');
        await Promise.all([
            fetchMeContext(),
            fetchAuthMe(),
            fetchPermittedRoles()
        ]);
        console.log('[VTID-01046] Auth boot complete');

        // Access control: Command Hub requires developer/admin/infra/staff role
        // VTID-01230-FIX: Check BOTH active_role AND permittedRoles to avoid
        // false 403 when active_role defaults to 'community' but user actually
        // has developer access. This fixes the "login → 403 → refresh twice" bug.
        var allowedRoles = ['developer', 'admin', 'infra', 'staff'];
        var userRole = state.meContext?.active_role || '';
        var isExafyAdmin = state.isSuperAdmin || state.authIdentity?.identity?.exafy_admin === true;
        var hasActiveAllowed = allowedRoles.includes(userRole);
        var hasPermittedAllowed = (state.permittedRoles || []).some(function(r) {
            return allowedRoles.includes(r);
        });
        // Also check memberships from /auth/me as a third source of truth
        var hasMembershipAllowed = (state.authIdentity?.memberships || []).some(function(m) {
            return allowedRoles.includes((m.role || '').toLowerCase());
        });

        if (!isExafyAdmin && !hasActiveAllowed && !hasPermittedAllowed && !hasMembershipAllowed) {
            console.warn('[Command Hub] Access denied — active_role=' + userRole +
                ', permitted=' + JSON.stringify(state.permittedRoles) +
                ', memberships=' + JSON.stringify((state.authIdentity?.memberships || []).map(function(m) { return m.role; })));
            document.getElementById('root').innerHTML =
                '<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:100vh;color:#fff;text-align:center;padding:2rem;">' +
                '<h1 style="font-size:2rem;margin-bottom:1rem;">403 — Access Denied</h1>' +
                '<p style="color:#aaa;max-width:400px;">Command Hub requires Developer or Admin access.<br>Your current role: <strong>' + (userRole || 'none') + '</strong></p>' +
                '<p style="color:#666;margin-top:2rem;">Contact your administrator to request access.</p>' +
                '</div>';
            return;
        }

        // Command Hub always operates in Developer context
        // VTID-01230-FIX: Determine the best allowed role to switch to.
        // Prefer 'developer' if permitted, otherwise pick the first allowed role from permitted list.
        var bestRole = 'developer';
        if (!allowedRoles.includes(userRole)) {
            // Active role is not allowed (e.g. 'community') — pick the best from permitted/membership
            var allUserRoles = (state.permittedRoles || []).concat(
                (state.authIdentity?.memberships || []).map(function(m) { return (m.role || '').toLowerCase(); })
            );
            if (allUserRoles.includes('developer')) {
                bestRole = 'developer';
            } else {
                // Pick first allowed role the user actually has
                for (var i = 0; i < allowedRoles.length; i++) {
                    if (allUserRoles.includes(allowedRoles[i])) {
                        bestRole = allowedRoles[i];
                        break;
                    }
                }
            }
        } else {
            bestRole = userRole;
        }

        var capitalBestRole = bestRole.charAt(0).toUpperCase() + bestRole.slice(1);
        state.viewRole = capitalBestRole;
        localStorage.setItem('vitana.viewRole', capitalBestRole);
        // Sync meContext.active_role so API headers send the correct role
        // Without this, buildContextHeaders() sends the server-side role (e.g. 'community')
        // instead of 'developer', causing role-filtered APIs to return wrong data.
        if (state.meContext && state.meContext.active_role !== bestRole) {
            state.meContext.active_role = bestRole;
            // Persist server-side so next page load doesn't default to 'community' again
            setActiveRole(bestRole).catch(function(err) {
                console.warn('[Command Hub] Failed to persist ' + bestRole + ' role:', err);
            });
        }

        // Final UI refresh after auth data is in
        renderApp();

        // Load data in parallel after auth is established
        Promise.all([
            fetchTasks(),
            fetchTelemetrySnapshot(),
            fetchApprovals(true),
            fetchAutopilotRecommendationsCount()
        ]).catch(err => console.error('Data Fetch Error:', err));

        // VTID-AUTH-GUARD + BOOTSTRAP-DEV-6H-SESSION (v2): session monitor.
        //
        // The actual JWT refresh is now handled by the global fetch interceptor
        // installed at the top of this file (it catches any 401 in a developer
        // session, refreshes via /api/v1/auth/refresh, and replays the request
        // transparently). This loop has two remaining jobs:
        //
        //   1. For developer sessions: enforce a 6-hour idle-logout — if the
        //      user hasn't done anything (mousedown/keydown/scroll/touchstart)
        //      in 6h, log them out. We also proactively top up the token a
        //      few minutes before expiry so polling fetches don't have to eat
        //      a 401 round-trip.
        //   2. For non-developer roles: keep the previous "logout when JWT
        //      exp passes" behavior so community/admin/staff sessions still
        //      end at the 1h Supabase expiry as before.
        var DEV_IDLE_LOGOUT_MS = 6 * 60 * 60 * 1000;   // 6 hours
        var TOKEN_REFRESH_LEAD_MS = 5 * 60 * 1000;      // top up if <5m left

        function isDeveloperSession() {
            return (state.meContext && state.meContext.active_role === 'developer');
        }
        function markActivity() { state.lastActivityAt = Date.now(); }
        ['mousedown', 'keydown', 'scroll', 'touchstart'].forEach(function (evt) {
            document.addEventListener(evt, markActivity, { passive: true, capture: true });
        });

        async function checkTokenExpiry() {
            if (!state.authToken) return;
            var payload;
            try {
                var parts = state.authToken.split('.');
                if (parts.length !== 3) return;
                payload = JSON.parse(atob(parts[1]));
            } catch (e) {
                console.warn('[VTID-AUTH-GUARD] Cannot parse JWT — logging out');
                doLogout();
                return;
            }

            var expMs = (payload && payload.exp) ? payload.exp * 1000 : 0;
            var now = Date.now();

            if (isDeveloperSession()) {
                var idleMs = now - (state.lastActivityAt || now);
                if (idleMs >= DEV_IDLE_LOGOUT_MS) {
                    console.warn('[DEV-6H-SESSION] idle ' + Math.round(idleMs / 60000) + 'm — logging out');
                    doLogout();
                    return;
                }
                // Proactively refresh if we're inside the lead window; if it
                // fails, the next polling 401 will give the interceptor a
                // second chance, and only after THAT fails will the existing
                // 401 → doLogout() handlers fire.
                if (expMs && expMs - now <= TOKEN_REFRESH_LEAD_MS && typeof window.__vitana_performRefresh === 'function') {
                    try { await window.__vitana_performRefresh(); } catch (_) {}
                }
                return;
            }

            // Non-developer roles: keep the existing strict behavior.
            if (expMs && expMs < now) {
                console.warn('[VTID-AUTH-GUARD] JWT expired — logging out');
                doLogout();
            }
        }

        setInterval(checkTokenExpiry, 30000);
        document.addEventListener('visibilitychange', function () {
            if (document.visibilityState === 'visible') {
                if (isDeveloperSession()) markActivity();
                checkTokenExpiry();
            }
        });

        // Initialize unified VitanaOrb widget (voice overlay handled by orb-widget.js)
        if (window.VitanaOrb) {
            // VTID-AUTH-FIX: Pass auth token explicitly — init() disables auto-detection.
            window.VitanaOrb.init({
                authToken: state.authToken || '',
                showFab: false, // Command Hub has its own sidebar trigger
                initialContext: { current_route: window.location.pathname },
                onClose: function () {
                    state.orb.overlayVisible = false;
                    renderApp();
                },
                // VITANA-BRAIN: Handle ORB navigation directives with SPA routing.
                // Surface scoping: Command Hub serves /command-hub/* only. If the
                // Navigator ever returns a non-Command-Hub route (it shouldn't —
                // the backend is surface-scoped — but belt-and-suspenders against
                // catalog drift), refuse instead of falling back to the default
                // tab or teleporting the user out to the community app.
                onNavigationRequest: function (route, ctx) {
                    console.log('[VTOrb-Nav] Navigation requested: ' + route + ' (screen=' + (ctx && ctx.screen_id || 'unknown') + ')');
                    var pathOnly = route ? route.split('?')[0] : '';
                    if (!pathOnly || pathOnly.indexOf('/command-hub') !== 0) {
                        console.warn('[VTOrb-Nav] Refused cross-surface route (Command Hub is developer-only): ' + route);
                        return;
                    }
                    var parsed = getRouteFromPath(route);
                    if (parsed) {
                        handleModuleClick(parsed.section);
                        if (parsed.tab) {
                            handleTabClick(parsed.tab);
                        }
                        console.log('[VTOrb-Nav] SPA navigated to ' + parsed.section + '/' + parsed.tab);
                    }
                }
            });
        }

        // VTID-0520: Start Background Polling
        startCicdHealthPolling();
        startApprovalsBadgePolling();
        startOverviewDashboardPolling();

    } catch (e) {
        console.error('Critical Render Error:', e);
        document.body.innerHTML = `<div class="critical-error"><h1>Critical Error</h1><pre>${e.stack}</pre></div>`;
    }
});
