    sevSelect.innerHTML = severities.map(function (m) {
        var label = m === '' ? 'Any severity' : m;
        return '<option value="' + m + '"' + (filter.severity === m ? ' selected' : '') + '>' + label + '</option>';
    }).join('');
    sevSelect.onchange = function () { filter.severity = this.value; renderApp(); };
